import { create } from 'zustand';

/** Persisted symbol list localStorage key. */
const STORAGE_KEY = 'deskmodal:watchlist:symbols';

/** Default symbols when no persisted data exists. */
const DEFAULT_SYMBOLS = [
  'BTCUSDT',
  'ETHUSDT',
  'SOLUSDT',
  'BNBUSDT',
  'XRPUSDT',
  'ADAUSDT',
  'AVAXUSDT',
  'DOTUSDT',
  'LINKUSDT',
  'MATICUSDT',
];

function loadPersistedSymbols(): string[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed: unknown = JSON.parse(raw);
      if (Array.isArray(parsed) && parsed.every((s) => typeof s === 'string')) {
        return parsed as string[];
      }
    }
  } catch {
    // Storage unavailable or corrupted — use defaults
  }
  return DEFAULT_SYMBOLS;
}

function persistSymbols(symbols: string[]): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(symbols));
  } catch {
    // Storage full or unavailable — silently ignore
  }
}

/** Maximum number of sparkline data points per symbol. */
const MAX_SPARKLINE_POINTS = 30;

export interface WatchlistStore {
  /** Ordered list of symbols in the watchlist. */
  symbols: string[];
  /** Historical price points per symbol for sparkline rendering (capped at MAX_SPARKLINE_POINTS). */
  sparklines: Map<string, number[]>;
  /** Add a symbol to the watchlist. No-op if already present. */
  addSymbol: (symbol: string) => void;
  /** Remove a symbol from the watchlist. */
  removeSymbol: (symbol: string) => void;
  /** Append a price point to the sparkline history for a symbol. */
  pushSparklinePoint: (symbol: string, price: number) => void;
}

export const useWatchlistStore = create<WatchlistStore>()((set, get) => ({
  symbols: loadPersistedSymbols(),
  sparklines: new Map(),

  addSymbol: (symbol: string) => {
    const { symbols } = get();
    if (symbols.includes(symbol)) return;
    const next = [...symbols, symbol];
    persistSymbols(next);
    set({ symbols: next });
  },

  removeSymbol: (symbol: string) => {
    const { symbols, sparklines } = get();
    const next = symbols.filter((s) => s !== symbol);
    persistSymbols(next);
    const nextSparklines = new Map(sparklines);
    nextSparklines.delete(symbol);
    set({ symbols: next, sparklines: nextSparklines });
  },

  pushSparklinePoint: (symbol: string, price: number) => {
    const { sparklines } = get();
    const nextSparklines = new Map(sparklines);
    const existing = nextSparklines.get(symbol) ?? [];
    const updated = existing.length >= MAX_SPARKLINE_POINTS
      ? [...existing.slice(1), price]
      : [...existing, price];
    nextSparklines.set(symbol, updated);
    set({ sparklines: nextSparklines });
  },
}));
