import { forwardRef } from 'react';
import { IconButton, Tooltip } from '../primitives';
import { Camera } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ScreenshotButton                                                          */
/*  Single IconButton with Camera icon for screenshot functionality.         */
/*  Uses IconButton + Tooltip with --ts-button-ghost-* tokens.               */
/* -------------------------------------------------------------------------- */

export interface ScreenshotButtonProps {
  /** Called when screenshot is triggered. */
  onScreenshot: () => void;
  /** Whether the button is disabled. */
  disabled?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-screenshot-button-styles';

function ensureScreenshotButtonStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-screenshot-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureScreenshotButtonStyles();
}

/* ----- Component --------------------------------------------------------- */

export const ScreenshotButton = forwardRef<HTMLButtonElement, ScreenshotButtonProps>(
  function ScreenshotButton({ onScreenshot, disabled = false }, ref) {
    return (
      <Tooltip content="Take screenshot" side="bottom">
        <IconButton
          ref={ref}
          data-ts-screenshot-button=""
          icon={<Camera size={16} />}
          label="Take screenshot"
          variant="ghost"
          size="sm"
          disabled={disabled}
          onClick={onScreenshot}
        />
      </Tooltip>
    );
  },
);

ScreenshotButton.displayName = 'ScreenshotButton';
