import { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import type {
  WatchlistSection,
  WatchlistSymbol,
  HotlistCategory,
} from '@deskmodal/ui-components';
import { useMarketData, type PriceTick } from '@deskmodal/data-layer';
import { useWatchlistStore } from '../store/watchlist-store';
import { DEFAULT_EXCHANGE, derivePrecision } from '../watchlist-constants';

/**
 * Convert a PriceTick from the shared market data hook to a WatchlistSymbol.
 */
function priceTickToWatchlistSymbol(
  symbol: string,
  tick: PriceTick,
): WatchlistSymbol {
  const precision = derivePrecision(tick.last);
  const bid = tick.bid || undefined;
  const offer = tick.ask || undefined;
  const spread = bid && offer ? offer - bid : undefined;
  const changePercent = tick.changePercent24h ?? 0;
  const priceChange = tick.last * (changePercent / 100);
  const open = priceChange ? tick.last - priceChange : undefined;
  return {
    id: `${DEFAULT_EXCHANGE.toUpperCase()}:${symbol}`,
    symbol,
    exchange: DEFAULT_EXCHANGE,
    price: tick.last,
    priceChange,
    priceChangePercent: changePercent,
    precision,
    volume: tick.volume24h,
    bid,
    bidSize: tick.bestBidQty || undefined,
    offer,
    offerSize: tick.bestAskQty || undefined,
    spread,
    open,
    high: tick.high24h || undefined,
    low: tick.low24h || undefined,
  };
}

/**
 * Create a placeholder WatchlistSymbol for a symbol with no tick data yet.
 */
function placeholderSymbol(symbol: string): WatchlistSymbol {
  return {
    id: `${DEFAULT_EXCHANGE.toUpperCase()}:${symbol}`,
    symbol,
    exchange: DEFAULT_EXCHANGE,
    price: null,
    priceChange: null,
    priceChangePercent: null,
    precision: 2,
  };
}

/**
 * Manages watchlist symbol data, consuming real-time price data
 * from the shared `useMarketData()` hook.
 *
 * When FDC3 is unavailable, displays placeholder rows for persisted symbols.
 */
export function useWatchlistData(): {
  sections: WatchlistSection[];
  setSections: React.Dispatch<React.SetStateAction<WatchlistSection[]>>;
  allSymbols: WatchlistSymbol[];
  hotlistSymbols: (category: HotlistCategory) => WatchlistSymbol[];
} {
  const { symbols, sparklines, pushSparklinePoint } = useWatchlistStore();
  const marketData = useMarketData();

  /** Track which symbols have had their sparkline updated this version to avoid duplication. */
  const lastSparklineVersionRef = useRef(-1);

  /** Build WatchlistSymbol array from shared market data. */
  const allSymbols = useMemo((): WatchlistSymbol[] => {
    const shouldPushSparkline = lastSparklineVersionRef.current !== marketData.version;
    if (shouldPushSparkline) {
      lastSparklineVersionRef.current = marketData.version;
    }

    return symbols.map((sym) => {
      // Try both raw symbol and slash-separated format for lookup
      const tick = marketData.getQuote(sym) ?? marketData.getQuote(sym.replace(/([A-Z]+)(USDT|BUSD|USD|USDC)$/, '$1/$2'));
      const sparklineData = sparklines.get(sym);

      if (tick) {
        // Accumulate sparkline points from live data
        if (shouldPushSparkline) {
          pushSparklinePoint(sym, tick.last);
        }

        const watchlistSym = priceTickToWatchlistSymbol(sym, tick);
        if (sparklineData && sparklineData.length >= 2) {
          return { ...watchlistSym, sparklineData };
        }
        return watchlistSym;
      }
      return placeholderSymbol(sym);
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [symbols, sparklines, marketData.version]);

  const [sections, setSections] = useState<WatchlistSection[]>([]);

  /** Rebuild sections whenever the symbol list or tick data changes. */
  useEffect(() => {
    setSections([
      {
        id: 'watchlist',
        label: 'Watchlist',
        collapsed: false,
        symbols: allSymbols,
      },
    ]);
  }, [allSymbols]);

  /** Compute hotlist symbols filtered by category. */
  const hotlistSymbols = useCallback(
    (category: HotlistCategory): WatchlistSymbol[] => {
      const sorted = [...allSymbols];
      switch (category) {
        case 'gainers':
          sorted.sort((a, b) => (b.priceChangePercent ?? 0) - (a.priceChangePercent ?? 0));
          return sorted.filter((s) => (s.priceChangePercent ?? 0) > 0);
        case 'losers':
          sorted.sort((a, b) => (a.priceChangePercent ?? 0) - (b.priceChangePercent ?? 0));
          return sorted.filter((s) => (s.priceChangePercent ?? 0) < 0);
        case 'volume':
          sorted.sort((a, b) => (b.volume ?? 0) - (a.volume ?? 0));
          return sorted;
        case 'new':
          return sorted.slice(0, 10);
      }
    },
    [allSymbols],
  );

  return { sections, setSections, allSymbols, hotlistSymbols };
}
