import type { CSSProperties, ReactNode } from 'react';

/* -------------------------------------------------------------------------- */
/*  Badge                                                                     */
/*  Status indicator with variants.                                           */
/*  Uses --ts-badge-* tokens.                                                 */
/* -------------------------------------------------------------------------- */

type BadgeVariant = 'default' | 'success' | 'warning' | 'error' | 'info';

interface BadgeProps {
  /** Visual variant controlling background and text color. */
  variant?: BadgeVariant;
  /** Badge content. */
  children: ReactNode;
}

const VARIANT_STYLES: Record<BadgeVariant, CSSProperties> = {
  default: {
    background: 'var(--ts-badge-bg)',
    color: 'var(--ts-badge-text)',
  },
  success: {
    background: 'var(--ts-badge-success-bg)',
    color: 'var(--ts-badge-success-text)',
  },
  warning: {
    background: 'var(--ts-badge-warning-bg)',
    color: 'var(--ts-badge-warning-text)',
  },
  error: {
    background: 'var(--ts-badge-error-bg)',
    color: 'var(--ts-badge-error-text)',
  },
  info: {
    background: 'var(--ts-badge-info-bg)',
    color: 'var(--ts-badge-info-text)',
  },
};

const baseStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 'var(--ts-badge-height)',
  padding: 'var(--ts-badge-padding-y) var(--ts-badge-padding-x)',
  fontSize: 'var(--ts-badge-font-size)',
  fontWeight: 'var(--ts-badge-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  borderRadius: 'var(--ts-badge-radius)',
  lineHeight: 1,
  whiteSpace: 'nowrap',
  userSelect: 'none',
  boxSizing: 'border-box',
};

export function Badge({ variant = 'default', children }: BadgeProps): React.JSX.Element {
  return (
    <span style={{ ...baseStyle, ...VARIANT_STYLES[variant] }} data-variant={variant}>
      {children}
    </span>
  );
}

Badge.displayName = 'Badge';
