import {
  Children,
  forwardRef,
  useCallback,
  useRef,
  useState,
  type CSSProperties,
  type KeyboardEvent,
  type ReactNode,
} from 'react';

export interface SplitPaneProps {
  /** Split direction */
  direction: 'horizontal' | 'vertical';
  /** Default size of the first pane as a percentage (0-100) */
  defaultSize?: number;
  /** Minimum size of the first pane as a percentage */
  minSize?: number;
  /** Maximum size of the first pane as a percentage */
  maxSize?: number;
  /** Callback when size changes */
  onResize?: (size: number) => void;
  /** Exactly two children for the two panes */
  children: ReactNode;
  /** Additional class name */
  className?: string;
}

const KEYBOARD_STEP = 2;

export const SplitPane = forwardRef<HTMLDivElement, SplitPaneProps>(
  function SplitPane(
    {
      direction,
      defaultSize = 50,
      minSize = 10,
      maxSize = 90,
      onResize,
      children,
      className,
    },
    ref,
  ) {
    const [size, setSize] = useState(defaultSize);
    const [dragging, setDragging] = useState(false);
    const [hovered, setHovered] = useState(false);
    const containerRef = useRef<HTMLDivElement | null>(null);
    const lastPosRef = useRef(0);

    const isHorizontal = direction === 'horizontal';

    const clampSize = useCallback(
      (value: number): number => Math.min(maxSize, Math.max(minSize, value)),
      [minSize, maxSize],
    );

    const handlePointerDown = useCallback(
      (event: React.PointerEvent<HTMLDivElement>) => {
        event.preventDefault();
        const target = event.currentTarget;
        target.setPointerCapture(event.pointerId);
        setDragging(true);
        lastPosRef.current = isHorizontal ? event.clientX : event.clientY;
      },
      [isHorizontal],
    );

    const handlePointerMove = useCallback(
      (event: React.PointerEvent<HTMLDivElement>) => {
        if (!dragging || !containerRef.current) return;
        const currentPos = isHorizontal ? event.clientX : event.clientY;
        const delta = currentPos - lastPosRef.current;
        lastPosRef.current = currentPos;

        const containerSize = isHorizontal
          ? containerRef.current.offsetWidth
          : containerRef.current.offsetHeight;

        if (containerSize === 0) return;

        const deltaPercent = (delta / containerSize) * 100;
        const newSize = clampSize(size + deltaPercent);

        if (newSize !== size) {
          setSize(newSize);
          onResize?.(newSize);
        }
      },
      [dragging, isHorizontal, size, clampSize, onResize],
    );

    const handlePointerUp = useCallback(
      (event: React.PointerEvent<HTMLDivElement>) => {
        event.currentTarget.releasePointerCapture(event.pointerId);
        setDragging(false);
      },
      [],
    );

    const handleKeyDown = useCallback(
      (event: KeyboardEvent<HTMLDivElement>) => {
        let delta = 0;

        if (isHorizontal) {
          if (event.key === 'ArrowLeft') delta = -KEYBOARD_STEP;
          else if (event.key === 'ArrowRight') delta = KEYBOARD_STEP;
        } else {
          if (event.key === 'ArrowUp') delta = -KEYBOARD_STEP;
          else if (event.key === 'ArrowDown') delta = KEYBOARD_STEP;
        }

        if (delta !== 0) {
          event.preventDefault();
          const newSize = clampSize(size + delta);
          if (newSize !== size) {
            setSize(newSize);
            onResize?.(newSize);
          }
        }
      },
      [isHorizontal, size, clampSize, onResize],
    );

    const childArray = Children.toArray(children);
    if (childArray.length !== 2) {
      throw new Error('SplitPane requires exactly 2 children');
    }

    const containerStyle: CSSProperties = {
      display: 'flex',
      flexDirection: isHorizontal ? 'row' : 'column',
      width: '100%',
      height: '100%',
      overflow: 'hidden',
    };

    const firstPaneStyle: CSSProperties = {
      [isHorizontal ? 'width' : 'height']: `${size}%`,
      overflow: 'hidden',
      flexShrink: 0,
    };

    const secondPaneStyle: CSSProperties = {
      flex: 1,
      overflow: 'hidden',
    };

    const dividerActive = dragging || hovered;

    const dividerStyle: CSSProperties = {
      position: 'relative',
      flexShrink: 0,
      [isHorizontal ? 'width' : 'height']: 'var(--ts-split-pane-divider-width)',
      background: dividerActive
        ? 'var(--ts-split-pane-divider-bg-hover)'
        : 'var(--ts-split-pane-divider-bg)',
      cursor: isHorizontal ? 'col-resize' : 'row-resize',
      touchAction: 'none',
      transition: `background var(--ts-duration-micro) ease`,
      outline: 'none',
    };

    /* Invisible hit area wider than the visible divider */
    const hitAreaStyle: CSSProperties = {
      position: 'absolute',
      [isHorizontal ? 'top' : 'left']: 0,
      [isHorizontal ? 'bottom' : 'right']: 0,
      [isHorizontal ? 'left' : 'top']: `calc(-1 * (var(--ts-split-pane-handle-width) - var(--ts-split-pane-divider-width)) / 2)`,
      [isHorizontal ? 'width' : 'height']: 'var(--ts-split-pane-handle-width)',
    };

    const setContainerRef = useCallback(
      (node: HTMLDivElement | null) => {
        containerRef.current = node;
        if (typeof ref === 'function') {
          ref(node);
        } else if (ref) {
          (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
        }
      },
      [ref],
    );

    return (
      <div ref={setContainerRef} className={className} style={containerStyle}>
        <div style={firstPaneStyle}>{childArray[0]}</div>
        <div
          role="separator"
          aria-orientation={direction}
          aria-valuenow={Math.round(size)}
          aria-valuemin={minSize}
          aria-valuemax={maxSize}
          tabIndex={0}
          style={dividerStyle}
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          onPointerCancel={handlePointerUp}
          onMouseEnter={() => setHovered(true)}
          onMouseLeave={() => setHovered(false)}
          onKeyDown={handleKeyDown}
        >
          <div style={hitAreaStyle} aria-hidden="true" />
        </div>
        <div style={secondPaneStyle}>{childArray[1]}</div>
      </div>
    );
  },
);
