import type { Context } from "../fdc3-types";
import type { MarketType, SymbolInfo } from "../core-types";

/** Extended fdc3.instrument context with crypto-specific metadata. */
export interface CryptoInstrumentContext extends Context {
  /** Standard FDC3 instrument type identifier. */
  type: "fdc3.instrument";
  /** Human-readable instrument name (e.g., "Bitcoin / Tether"). */
  name: string;
  /** Standard and extended identifiers. */
  id: {
    /** Exchange-specific ticker (e.g., "BTCUSDT"). */
    ticker: string;
    /** Financial Instrument Global Identifier (if available). */
    FIGI?: string;
    /** Blockchain network (for DEX instruments). */
    chain?: string;
    /** Token contract address (for DEX instruments). */
    contractAddress?: string;
    /** DEX liquidity pool address. */
    pairAddress?: string;
    /** Source exchange identifier. */
    exchange?: string;
  };
  /** Market identification (FDC3 standard field). */
  market?: {
    /** Market Identifier Code (ISO 10383). */
    MIC?: string;
    /** Market name. */
    name?: string;
  };
  /** Deskmodal crypto extension data. */
  "deskmodal.crypto"?: {
    /** Market type classification. */
    marketType: MarketType;
    /** Base asset symbol (e.g., "BTC"). */
    baseAsset: string;
    /** Quote asset symbol (e.g., "USDT"). */
    quoteAsset: string;
  };
}

/**
 * Create a CryptoInstrumentContext from a SymbolInfo.
 * Maps exchange-specific symbol metadata into the FDC3 instrument context format.
 */
export function createInstrumentContext(
  symbol: SymbolInfo
): CryptoInstrumentContext {
  const context: CryptoInstrumentContext = {
    type: "fdc3.instrument",
    name: symbol.name,
    id: {
      ticker: symbol.symbol,
      exchange: symbol.exchange,
    },
    "deskmodal.crypto": {
      marketType: symbol.marketType,
      baseAsset: symbol.baseAsset,
      quoteAsset: symbol.quoteAsset,
    },
  };

  if (symbol.chain) {
    context.id.chain = symbol.chain;
  }

  if (symbol.contractAddress) {
    context.id.contractAddress = symbol.contractAddress;
  }

  if (symbol.poolAddress) {
    context.id.pairAddress = symbol.poolAddress;
  }

  return context;
}
