import type { KeyboardShortcut, ParsedKeyCombo, ShortcutCategory } from './keyboard-shortcuts';
import { DEFAULT_SHORTCUTS } from './keyboard-shortcuts';

/** Handler invoked when a keyboard shortcut is triggered. */
export type ShortcutHandler = (action: string, shortcut: KeyboardShortcut) => void;

/** Configuration for the keyboard manager. */
export interface KeyboardManagerConfig {
  /** Custom shortcut overrides keyed by shortcut id. Overrides `keys` only. */
  readonly overrides?: Readonly<Record<string, string>>;
  /** Element to attach the keyboard listener to. Defaults to `document`. */
  readonly target?: EventTarget;
  /** When true, shortcuts are not processed if the active element is an input or textarea. */
  readonly ignoreInputElements?: boolean;
}

/**
 * Parse a human-readable key combination string into a structured representation.
 *
 * Accepts formats like "Ctrl+Z", "Shift+1", "Alt+F", "F11", "Escape", "Delete".
 * Modifiers are case-insensitive. The primary key is always lowercased.
 */
export function parseKeyCombo(combo: string): ParsedKeyCombo {
  const parts = combo.split('+');
  let ctrl = false;
  let shift = false;
  let alt = false;
  let meta = false;
  let key = '';

  for (const part of parts) {
    const normalized = part.trim().toLowerCase();
    switch (normalized) {
      case 'ctrl':
      case 'control':
        ctrl = true;
        break;
      case 'shift':
        shift = true;
        break;
      case 'alt':
        alt = true;
        break;
      case 'meta':
      case 'cmd':
      case 'command':
      case 'win':
        meta = true;
        break;
      default:
        key = normalized;
        break;
    }
  }

  return { key, ctrl, shift, alt, meta };
}

/**
 * Determine if a keyboard event matches a shortcut's key combination.
 *
 * Compares modifiers (ctrl, shift, alt, meta) and the primary key against the event.
 */
export function matchesEvent(event: KeyboardEvent, shortcut: KeyboardShortcut): boolean {
  const combo = parseKeyCombo(shortcut.keys);
  return matchesParsedCombo(event, combo);
}

/**
 * Determine if a keyboard event matches a pre-parsed key combination.
 * More efficient than `matchesEvent` when checking many shortcuts per event.
 */
function matchesParsedCombo(event: KeyboardEvent, combo: ParsedKeyCombo): boolean {
  if (event.ctrlKey !== combo.ctrl) return false;
  if (event.shiftKey !== combo.shift) return false;
  if (event.altKey !== combo.alt) return false;
  if (event.metaKey !== combo.meta) return false;

  const eventKey = event.key.toLowerCase();
  return eventKey === combo.key;
}

/** Cached entry for a registered shortcut with its pre-parsed combo. */
interface ShortcutEntry {
  readonly shortcut: KeyboardShortcut;
  readonly combo: ParsedKeyCombo;
}

/**
 * Manages keyboard shortcut registration, listening, and dispatch.
 *
 * Attach a handler to receive action strings when the user presses a registered
 * shortcut. Supports user-customized key bindings via overrides.
 */
export class KeyboardManager {
  private readonly entries: ShortcutEntry[];
  private readonly handlers = new Set<ShortcutHandler>();
  private readonly target: EventTarget;
  private readonly ignoreInputElements: boolean;
  private readonly boundKeyDown: (event: Event) => void;
  private active = false;

  constructor(config: KeyboardManagerConfig = {}) {
    this.target = config.target ?? globalThis.document;
    this.ignoreInputElements = config.ignoreInputElements ?? true;

    const overrides = config.overrides ?? {};
    this.entries = DEFAULT_SHORTCUTS.map((shortcut) => {
      const keys = overrides[shortcut.id] ?? shortcut.keys;
      const resolved: KeyboardShortcut = keys !== shortcut.keys
        ? { ...shortcut, keys }
        : shortcut;
      return {
        shortcut: resolved,
        combo: parseKeyCombo(resolved.keys),
      };
    });

    this.boundKeyDown = (event: Event) => {
      this.handleKeyDown(event as KeyboardEvent);
    };
  }

  /** Start listening for keyboard events on the target. */
  start(): void {
    if (this.active) return;
    this.active = true;
    this.target.addEventListener('keydown', this.boundKeyDown);
  }

  /** Stop listening for keyboard events. */
  stop(): void {
    if (!this.active) return;
    this.active = false;
    this.target.removeEventListener('keydown', this.boundKeyDown);
  }

  /** Register a handler that receives action strings when shortcuts are triggered. Returns an unsubscribe function. */
  onShortcut(handler: ShortcutHandler): () => void {
    this.handlers.add(handler);
    let removed = false;
    return () => {
      if (removed) return;
      removed = true;
      this.handlers.delete(handler);
    };
  }

  /** Get all registered shortcuts, optionally filtered by category. */
  getShortcuts(category?: ShortcutCategory): readonly KeyboardShortcut[] {
    if (category === undefined) {
      return this.entries.map((e) => e.shortcut);
    }
    return this.entries
      .filter((e) => e.shortcut.category === category)
      .map((e) => e.shortcut);
  }

  /** Find a shortcut by its id. */
  getShortcutById(id: string): KeyboardShortcut | undefined {
    return this.entries.find((e) => e.shortcut.id === id)?.shortcut;
  }

  /** Tear down the manager, removing all listeners and handlers. */
  dispose(): void {
    this.stop();
    this.handlers.clear();
  }

  private handleKeyDown(event: KeyboardEvent): void {
    if (this.ignoreInputElements && isInputElement(event.target)) {
      return;
    }

    for (const entry of this.entries) {
      if (matchesParsedCombo(event, entry.combo)) {
        event.preventDefault();
        event.stopPropagation();
        for (const handler of this.handlers) {
          handler(entry.shortcut.action, entry.shortcut);
        }
        return;
      }
    }
  }
}

/** Check whether an event target is an input, textarea, or contenteditable element. */
function isInputElement(target: EventTarget | null): boolean {
  if (target === null) return false;
  if (!(target instanceof HTMLElement)) return false;
  const tag = target.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
  return target.isContentEditable;
}
