import type { IndicatorConfig } from './indicators';

/** Supported chart series types. */
export enum SeriesType {
  Candlestick = "candlestick",
  Bar = "bar",
  Line = "line",
  Area = "area",
  Baseline = "baseline",
  HeikinAshi = "heikin-ashi",
  HollowCandles = "hollow-candles",
  Columns = "columns",
  LineWithMarkers = "line-with-markers",
  StepLine = "step-line",
  HLCArea = "hlc-area",
  Renko = "renko",
  Kagi = "kagi",
  LineBreak = "line-break",
  PointAndFigure = "point-and-figure",
  Range = "range",
  VolumeFootprint = "volume-footprint",
  MarketProfile = "market-profile",
  SessionVolumeProfile = "session-volume-profile",
  HighLow = "high-low",
  VolumeCandles = "volume-candles",
}

/** Price scale rendering mode. */
export enum PriceScaleMode {
  Linear = "linear",
  Logarithmic = "logarithmic",
  Percentage = "percentage",
  IndexedTo100 = "indexed-to-100",
}

/** Standard timeframe definitions. */
export interface Timeframe {
  /** Display label (e.g., "1m", "4h", "1D"). */
  label: string;
  /** Duration in seconds. */
  seconds: number;
  /** Category for grouping in UI. */
  category: "seconds" | "minutes" | "hours" | "days" | "weeks" | "months";
}

/** Chart configuration for a single chart instance. */
export interface ChartConfig {
  /** Primary instrument displayed on the chart. */
  symbol: string;
  /** Active timeframe. */
  timeframe: Timeframe;
  /** Primary series type (candlestick, line, etc.). */
  seriesType: SeriesType;
  /** Price scale mode. */
  priceScaleMode: PriceScaleMode;
  /** Whether the price scale auto-fits to visible data. */
  autoScale: boolean;
  /** Whether grid lines are visible. */
  showGrid: boolean;
  /** Whether the watermark is visible. */
  showWatermark: boolean;
  /** Active indicator configurations. */
  indicators: IndicatorConfig[];
  /** Source exchange identifier. */
  exchange: string;
}
