/**
 * Seeds sparkline data with historical close prices via the GetHistory intent.
 *
 * On mount, fetches the last 30 hourly candles for each watchlist symbol
 * and populates the sparklines map in the watchlist store. This gives
 * immediate visual context instead of waiting for tick-by-tick accumulation.
 */

import { useEffect, useRef } from 'react';
import { useFdc3, INTENTS } from '@deskmodal/fdc3';
import type { Context } from '@deskmodal/fdc3';
import { useWatchlistStore } from '../store/watchlist-store';

/** OHLCV candle returned from the GetHistory intent result. */
interface OHLCVCandle {
  timestamp: number;
  open: number;
  high: number;
  low: number;
  close: number;
  volume: number;
}

/** Maximum number of candles to fetch for sparkline. */
const SPARKLINE_CANDLE_COUNT = 30;

export function useSparklineHistory(): void {
  const fdc3 = useFdc3();
  const symbols = useWatchlistStore((s) => s.symbols);
  const seededRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    if (!fdc3) return;

    // Read sparklines from store directly (not from a selector) to avoid
    // re-running this effect on every price tick. The sparklines Map gets
    // a new reference each time pushSparklinePoint() is called, which
    // would cause this effect to tear down and re-run constantly.
    const currentSparklines = useWatchlistStore.getState().sparklines;

    // Find symbols that don't have enough sparkline data yet
    const needsHistory = symbols.filter((sym) => {
      if (seededRef.current.has(sym)) return false;
      const existing = currentSparklines.get(sym);
      return !existing || existing.length < 5;
    });

    if (needsHistory.length === 0) return;

    // Fetch history for each symbol (rate-limited, 3 concurrent max)
    let cancelled = false;
    const queue = [...needsHistory];
    const MAX_CONCURRENT = 3;
    let active = 0;

    function fetchNext() {
      if (cancelled || queue.length === 0 || active >= MAX_CONCURRENT) return;

      const sym = queue.shift();
      if (!sym) return;
      active++;
      seededRef.current.add(sym);

      const ctx = {
        type: 'fdc3.instrument',
        name: sym,
        id: { ticker: sym },
        'deskmodal.history': {
          timeframe: '1h',
          count: SPARKLINE_CANDLE_COUNT,
        },
      } as unknown as Context;

      fdc3!.raiseIntent(INTENTS.GetHistory, ctx)
        .then(async (resolution) => {
          if (cancelled) return;
          try {
            const result = await resolution.getResult();
            if (!result || cancelled) return;
            const ohlcvCtx = result as Context & { 'deskmodal.ohlcv'?: { candles?: OHLCVCandle[] } };
            const candles = ohlcvCtx['deskmodal.ohlcv']?.candles;
            if (candles && Array.isArray(candles) && candles.length > 0) {
              const closes = candles.map((c) => c.close);
              // Seed store sparklines — only if we don't have better data yet
              const store = useWatchlistStore.getState();
              const existing = store.sparklines.get(sym);
              if (!existing || existing.length < closes.length) {
                const nextSparklines = new Map(store.sparklines);
                nextSparklines.set(sym, closes);
                useWatchlistStore.setState({ sparklines: nextSparklines });
              }
            }
          } catch {
            // Intent result retrieval failed — symbol may not have history
          }
        })
        .catch(() => {
          // Intent delivery failed — price-feed service may not support this symbol
        })
        .finally(() => {
          active--;
          if (!cancelled) fetchNext();
        });

      fetchNext(); // Start next concurrent
    }

    fetchNext();

    return () => {
      cancelled = true;
    };
  }, [fdc3, symbols]);
}
