import { useCallback, useMemo, type CSSProperties } from 'react';
import { IconButton } from '../../primitives';
import { Plus } from 'lucide-react';
import { FilterChip } from './FilterChip';
import { FilterRangeSlider } from './FilterRangeSlider';
import { FilterPresetSelector } from './FilterPresetSelector';

/* -------------------------------------------------------------------------- */
/*  FilterBar                                                                 */
/*  Horizontal scrollable row of FilterChip components with preset support.   */
/*  Composes FilterChip, FilterRangeSlider, FilterPresetSelector.             */
/*  Uses --ts-screener-filter-bar-* tokens.                                   */
/* -------------------------------------------------------------------------- */

export interface FilterRangeConfig {
  min: number;
  max: number;
  step?: number;
  formatValue?: (value: number) => string;
  presets?: Array<{ label: string; value: [number, number] }>;
}

export interface FilterSelectConfig {
  options: Array<{ value: string; label: string }>;
  multiple?: boolean;
}

export interface FilterDefinition {
  /** Unique filter field key (e.g., "marketCap", "volume24h"). */
  field: string;
  /** Display label for the filter chip. */
  label: string;
  /** Filter control type. */
  type: 'range' | 'select' | 'multi-select';
  /** Configuration for the filter control. */
  config: FilterRangeConfig | FilterSelectConfig;
}

export interface ActiveFilter {
  field: string;
  operator: 'gt' | 'lt' | 'gte' | 'lte' | 'eq' | 'between' | 'in';
  value: number | [number, number] | string[];
}

export interface FilterBarProps {
  /** Available filter definitions. */
  filters: FilterDefinition[];
  /** Currently active filters. */
  activeFilters: ActiveFilter[];
  /** Called when filters change. */
  onFiltersChange: (filters: ActiveFilter[]) => void;
  /** Filter presets for the preset selector. */
  presets?: Array<{ id: string; name: string }>;
  /** Currently selected preset ID. */
  selectedPresetId?: string | null;
  /** Called when a preset is selected. */
  onPresetSelect?: (presetId: string) => void;
  /** Called when saving a new preset. */
  onPresetSave?: (name: string) => void;
  /** Called when deleting a preset. */
  onPresetDelete?: (presetId: string) => void;
  /** Total result count to display (e.g., "3,025 results"). */
  resultCount?: number;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-filter-bar-styles';

function ensureFilterBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-filter-bar]::-webkit-scrollbar {
      display: none;
    }
    [data-ts-filter-bar] {
      scrollbar-width: none;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureFilterBarStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const barStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-screener-filter-bar-gap, var(--ts-space-2))',
  height: 'var(--ts-screener-filter-bar-height, 40px)',
  padding: '0 var(--ts-screener-filter-bar-padding-x, var(--ts-space-3))',
  background: 'var(--ts-screener-filter-bar-bg, var(--ts-toolbar-bg))',
  borderBottom: '1px solid var(--ts-screener-filter-bar-border, var(--ts-toolbar-border))',
  overflowX: 'auto',
  scrollbarWidth: 'none',
  flexShrink: 0,
};

const resultCountStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-tertiary)',
  whiteSpace: 'nowrap',
  fontVariantNumeric: 'tabular-nums',
  flexShrink: 0,
};

const chipsContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  flex: 1,
  overflow: 'hidden',
};

const selectOptionsContainerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
  maxHeight: 200,
  overflowY: 'auto',
};

const selectOptionStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: '6px var(--ts-space-2)',
  fontSize: 'var(--ts-font-sm)',
  cursor: 'pointer',
  borderRadius: 'var(--ts-radius-sm)',
  color: 'var(--ts-text-primary)',
  transition: 'background 100ms',
};

/* ----- Helpers ----------------------------------------------------------- */

function getFilterValueSummary(
  definition: FilterDefinition,
  activeFilter: ActiveFilter | undefined,
): string | null {
  if (activeFilter === undefined) return null;

  if (definition.type === 'range') {
    const val = activeFilter.value;
    const cfg = definition.config as FilterRangeConfig;
    const fmt = cfg.formatValue ?? ((v: number) => v.toLocaleString());
    if (Array.isArray(val) && typeof val[0] === 'number' && typeof val[1] === 'number') {
      return `${fmt(val[0])} - ${fmt(val[1])}`;
    }
    const ops: Record<string, string> = { gt: '>', lt: '<', gte: '>=', lte: '<=', eq: '=' };
    return `${ops[activeFilter.operator] ?? ''}${fmt(val as number)}`;
  }

  if (Array.isArray(activeFilter.value)) {
    const vals = activeFilter.value as string[];
    if (vals.length <= 2) return vals.join(', ');
    return `${vals.length} selected`;
  }

  return String(activeFilter.value);
}

function formatResultCount(count: number): string {
  return `${count.toLocaleString()} results`;
}

/* ----- Component --------------------------------------------------------- */

export function FilterBar({
  filters,
  activeFilters,
  onFiltersChange,
  presets,
  selectedPresetId,
  onPresetSelect,
  onPresetSave,
  onPresetDelete,
  resultCount,
}: FilterBarProps): React.JSX.Element {
  const activeFilterMap = useMemo(() => {
    const map = new Map<string, ActiveFilter>();
    for (const af of activeFilters) {
      map.set(af.field, af);
    }
    return map;
  }, [activeFilters]);

  const handleClearFilter = useCallback(
    (field: string) => {
      onFiltersChange(activeFilters.filter((af) => af.field !== field));
    },
    [activeFilters, onFiltersChange],
  );

  const handleRangeChange = useCallback(
    (field: string, value: [number, number]) => {
      const existing = activeFilters.filter((af) => af.field !== field);
      onFiltersChange([...existing, { field, operator: 'between', value }]);
    },
    [activeFilters, onFiltersChange],
  );

  const handleSelectOptionToggle = useCallback(
    (field: string, optionValue: string) => {
      const existing = activeFilterMap.get(field);
      const currentValues = (existing?.value as string[] | undefined) ?? [];
      const newValues = currentValues.includes(optionValue)
        ? currentValues.filter((v) => v !== optionValue)
        : [...currentValues, optionValue];

      if (newValues.length === 0) {
        handleClearFilter(field);
        return;
      }

      const others = activeFilters.filter((af) => af.field !== field);
      onFiltersChange([...others, { field, operator: 'in', value: newValues }]);
    },
    [activeFilterMap, activeFilters, onFiltersChange, handleClearFilter],
  );

  return (
    <div data-ts-filter-bar="" style={barStyle} role="toolbar" aria-label="Screener filters">
      {resultCount !== undefined && (
        <span style={resultCountStyle} aria-live="polite">
          {formatResultCount(resultCount)}
        </span>
      )}

      <div style={chipsContainerStyle}>
        {filters.map((def) => {
          const activeFilter = activeFilterMap.get(def.field);
          const isActive = activeFilter !== undefined;
          const summary = getFilterValueSummary(def, activeFilter);

          return (
            <FilterChip
              key={def.field}
              label={def.label}
              valueSummary={summary}
              active={isActive}
              onClear={() => handleClearFilter(def.field)}
            >
              {def.type === 'range' && (
                <FilterRangeSlider
                  min={(def.config as FilterRangeConfig).min}
                  max={(def.config as FilterRangeConfig).max}
                  step={(def.config as FilterRangeConfig).step}
                  formatValue={(def.config as FilterRangeConfig).formatValue}
                  presets={(def.config as FilterRangeConfig).presets}
                  value={
                    isActive && Array.isArray(activeFilter.value)
                      ? activeFilter.value as [number, number]
                      : [(def.config as FilterRangeConfig).min, (def.config as FilterRangeConfig).max]
                  }
                  onValueChange={(val) => handleRangeChange(def.field, val)}
                  label={def.label}
                />
              )}
              {(def.type === 'select' || def.type === 'multi-select') && (
                <div style={selectOptionsContainerStyle}>
                  {(def.config as FilterSelectConfig).options.map((opt) => {
                    const currentValues = (activeFilter?.value as string[] | undefined) ?? [];
                    const isChecked = currentValues.includes(opt.value);
                    return (
                      <button
                        key={opt.value}
                        type="button"
                        style={{
                          ...selectOptionStyle,
                          background: isChecked ? 'var(--ts-accent-subtle)' : 'transparent',
                        }}
                        onClick={() => handleSelectOptionToggle(def.field, opt.value)}
                        onMouseEnter={(e) => {
                          if (!isChecked) {
                            e.currentTarget.style.background = 'var(--ts-menu-item-bg-hover)';
                          }
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = isChecked ? 'var(--ts-accent-subtle)' : 'transparent';
                        }}
                        role="option"
                        aria-selected={isChecked}
                      >
                        {opt.label}
                      </button>
                    );
                  })}
                </div>
              )}
            </FilterChip>
          );
        })}

        <IconButton
          icon={<Plus size={14} />}
          label="Add filter"
          variant="ghost"
          size="sm"
        />
      </div>

      {presets !== undefined && onPresetSelect !== undefined && onPresetSave !== undefined && onPresetDelete !== undefined && (
        <FilterPresetSelector
          presets={presets}
          selectedPresetId={selectedPresetId ?? null}
          onPresetSelect={onPresetSelect}
          onPresetSave={onPresetSave}
          onPresetDelete={onPresetDelete}
        />
      )}
    </div>
  );
}

FilterBar.displayName = 'FilterBar';
