import { create } from 'zustand';

/** Persisted subscription localStorage key. */
const STORAGE_KEY = 'deskmodal:watchlist:subscriptions';

/** A single exchange-symbol subscription. */
export interface Subscription {
  /** Exchange identifier (e.g., 'binance', 'coinbase'). */
  exchangeId: string;
  /** Trading pair in exchange format (e.g., 'BTC/USDT'). */
  symbol: string;
}

/** Available exchanges and their display metadata. */
export interface ExchangeInfo {
  readonly id: string;
  readonly name: string;
}

export const EXCHANGES: ExchangeInfo[] = [
  { id: 'binance', name: 'Binance' },
  { id: 'coinbase', name: 'Coinbase' },
  { id: 'bybit', name: 'Bybit' },
  { id: 'okx', name: 'OKX' },
  { id: 'kraken', name: 'Kraken' },
  { id: 'gemini', name: 'Gemini' },
];

function loadPersistedSubscriptions(): Subscription[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed: unknown = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed.filter(
          (s): s is Subscription =>
            typeof s === 'object' &&
            s !== null &&
            typeof (s as Subscription).exchangeId === 'string' &&
            typeof (s as Subscription).symbol === 'string',
        );
      }
    }
  } catch {
    // Storage unavailable or corrupted — use defaults
  }
  return [];
}

function persistSubscriptions(subs: Subscription[]): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(subs));
  } catch {
    // Storage full or unavailable — silently ignore
  }
}

export interface SubscriptionStore {
  /** All active subscriptions. */
  subscriptions: Subscription[];
  /** Add a subscription. No-op if already present. */
  addSubscription: (exchangeId: string, symbol: string) => void;
  /** Remove a subscription. */
  removeSubscription: (exchangeId: string, symbol: string) => void;
  /** Get subscriptions for a specific exchange. */
  getByExchange: (exchangeId: string) => Subscription[];
}

export const useSubscriptionStore = create<SubscriptionStore>()((set, get) => ({
  subscriptions: loadPersistedSubscriptions(),

  addSubscription: (exchangeId: string, symbol: string) => {
    const { subscriptions } = get();
    const exists = subscriptions.some(
      (s) => s.exchangeId === exchangeId && s.symbol === symbol,
    );
    if (exists) return;
    const next = [...subscriptions, { exchangeId, symbol }];
    persistSubscriptions(next);
    set({ subscriptions: next });
  },

  removeSubscription: (exchangeId: string, symbol: string) => {
    const { subscriptions } = get();
    const next = subscriptions.filter(
      (s) => !(s.exchangeId === exchangeId && s.symbol === symbol),
    );
    persistSubscriptions(next);
    set({ subscriptions: next });
  },

  getByExchange: (exchangeId: string) => {
    const { subscriptions } = get();
    return subscriptions.filter((s) => s.exchangeId === exchangeId);
  },
}));
