import { useCallback, useMemo, useState, type CSSProperties } from 'react';
import { Panel, Tabs, Input, IconButton, Button, Skeleton, EmptyState, VirtualList } from '../../primitives';
import { AlertRow } from '../../financial/AlertRow';
import { AlertStatusBadge } from './AlertStatusBadge';
import { AlertGroupHeader } from './AlertGroupHeader';
import { Plus, Search, Bell } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  AlertManagerPanel                                                         */
/*  Full alert management panel with tabs, search, grouping, and              */
/*  virtualized alert list. Composes Panel, Tabs, VirtualList, AlertRow.      */
/*  Uses --ts-panel-*, --ts-tab-*, --ts-input-* tokens.                      */
/* -------------------------------------------------------------------------- */

export interface AlertItem {
  id: string;
  symbol: string;
  condition: string;
  price: number;
  status: 'active' | 'triggered' | 'expired' | 'disabled';
  createdAt: string;
  triggeredAt?: string;
  frequency: string;
  channels: string[];
}

type TabFilter = 'all' | 'active' | 'triggered' | 'expired';
type GroupBy = 'none' | 'symbol' | 'status';

export interface AlertManagerPanelProps {
  /** All alerts to display. */
  alerts: AlertItem[];
  /** Currently selected tab filter. */
  activeTab: TabFilter;
  /** Called when tab changes. */
  onTabChange: (tab: TabFilter) => void;
  /** Grouping mode for alerts. */
  groupBy: GroupBy;
  /** Called when grouping changes. */
  onGroupByChange: (groupBy: GroupBy) => void;
  /** Called when an alert's toggle (enable/disable) is clicked. */
  onAlertToggle: (alertId: string) => void;
  /** Called when edit is clicked on an alert. */
  onAlertEdit: (alertId: string) => void;
  /** Called when delete is clicked on an alert. */
  onAlertDelete: (alertId: string) => void;
  /** Called when "Create Alert" action is triggered. */
  onCreateAlert: () => void;
  /** Whether the panel is in loading state. */
  loading?: boolean;
  /** Search/filter query string. */
  searchQuery?: string;
  /** Called when search query changes. */
  onSearchQueryChange?: (query: string) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-alert-manager-panel-styles';

function ensureAlertManagerPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-alert-manager-panel] [data-ts-alert-manager-group-selector] button:hover {
      background: oklch(0.50 0.005 260 / 0.08);
    }
    [data-ts-alert-manager-panel] [data-ts-alert-manager-group-selector] button[data-active] {
      background: oklch(0.50 0.005 260 / 0.12);
      color: var(--ts-text-primary);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertManagerPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const searchBarStyle: CSSProperties = {
  padding: 'var(--ts-space-2) var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
};

const tabBarStyle: CSSProperties = {
  padding: '0 var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
};

const groupBarStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  padding: 'var(--ts-space-1) var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
};

const groupLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  marginRight: 'var(--ts-space-1)',
};

const groupBtnStyle: CSSProperties = {
  all: 'unset',
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
  padding: '2px 8px',
  borderRadius: 'var(--ts-radius-sm)',
  cursor: 'pointer',
  transition: 'background 100ms, color 100ms',
  boxSizing: 'border-box',
};

const listContainerStyle: CSSProperties = {
  height: 400,
};

const countBadgeStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  marginLeft: 'var(--ts-space-1)',
};

const skeletonRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 48,
  padding: '0 var(--ts-space-3)',
  gap: 'var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-border-subtle)',
};

/* ----- Component --------------------------------------------------------- */

export function AlertManagerPanel({
  alerts,
  activeTab,
  onTabChange,
  groupBy,
  onGroupByChange,
  onAlertToggle,
  onAlertEdit,
  onAlertDelete,
  onCreateAlert,
  loading = false,
  searchQuery = '',
  onSearchQueryChange,
}: AlertManagerPanelProps): React.JSX.Element {
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({});

  const filteredAlerts = useMemo(() => {
    let result = alerts;

    if (activeTab !== 'all') {
      result = result.filter((a) => a.status === activeTab);
    }

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(
        (a) =>
          a.symbol.toLowerCase().includes(q) ||
          a.condition.toLowerCase().includes(q),
      );
    }

    return result;
  }, [alerts, activeTab, searchQuery]);

  const tabCounts = useMemo(() => ({
    all: alerts.length,
    active: alerts.filter((a) => a.status === 'active').length,
    triggered: alerts.filter((a) => a.status === 'triggered').length,
    expired: alerts.filter((a) => a.status === 'expired').length,
  }), [alerts]);

  const groups = useMemo(() => {
    if (groupBy === 'none') return null;

    const grouped: Record<string, AlertItem[]> = {};
    for (const alert of filteredAlerts) {
      const key = groupBy === 'symbol' ? alert.symbol : alert.status;
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(alert);
    }
    return grouped;
  }, [filteredAlerts, groupBy]);

  const toggleGroup = useCallback((groupKey: string) => {
    setExpandedGroups((prev) => ({
      ...prev,
      [groupKey]: prev[groupKey] === false ? true : prev[groupKey] === undefined ? false : !prev[groupKey],
    }));
  }, []);

  const isGroupExpanded = useCallback(
    (groupKey: string) => expandedGroups[groupKey] !== false,
    [expandedGroups],
  );

  const createAction = useMemo(
    () => (
      <IconButton
        icon={<Plus size={16} />}
        label="Create alert"
        size="sm"
        variant="ghost"
        onClick={onCreateAlert}
        data-testid="create-alert"
      />
    ),
    [onCreateAlert],
  );

  const renderAlertItem = useCallback(
    (alert: AlertItem) => (
      <AlertRow
        key={alert.id}
        symbol={alert.symbol}
        condition={alert.condition}
        price={alert.price}
        status={alert.status === 'expired' ? 'disabled' : alert.status === 'triggered' ? 'triggered' : alert.status}
        onToggle={() => onAlertToggle(alert.id)}
        onEdit={() => onAlertEdit(alert.id)}
        onDelete={() => onAlertDelete(alert.id)}
      />
    ),
    [onAlertToggle, onAlertEdit, onAlertDelete],
  );

  const renderContent = () => {
    if (loading) {
      return (
        <div data-testid="loading-skeleton">
          {Array.from({ length: 5 }, (_, i) => (
            <div key={i} style={skeletonRowStyle} data-testid="skeleton-row">
              <Skeleton width={8} height={8} circle />
              <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 4 }}>
                <Skeleton width="50%" height={14} />
                <Skeleton width="70%" height={12} />
              </div>
              <Skeleton width={60} height={14} />
            </div>
          ))}
        </div>
      );
    }

    if (filteredAlerts.length === 0) {
      return (
        <EmptyState
          icon={<Bell size={32} />}
          title="No alerts"
          description={searchQuery ? 'No alerts match your search.' : 'Create your first alert to get started.'}
          action={
            !searchQuery ? (
              <Button variant="primary" size="sm" onClick={onCreateAlert}>
                Create Alert
              </Button>
            ) : undefined
          }
        />
      );
    }

    if (groups) {
      return (
        <div>
          {Object.entries(groups).map(([groupKey, groupAlerts]) => (
            <div key={groupKey}>
              <AlertGroupHeader
                label={groupKey}
                count={groupAlerts.length}
                expanded={isGroupExpanded(groupKey)}
                onExpandedChange={() => toggleGroup(groupKey)}
                icon={
                  groupBy === 'status' ? (
                    <AlertStatusBadge
                      status={groupKey as 'active' | 'triggered' | 'expired' | 'disabled'}
                      showLabel={false}
                      size="sm"
                    />
                  ) : undefined
                }
              />
              {isGroupExpanded(groupKey) ? (
                <div>
                  {groupAlerts.map(renderAlertItem)}
                </div>
              ) : null}
            </div>
          ))}
        </div>
      );
    }

    const VIRTUALIZE_THRESHOLD = 50;
    const useVirtualization = filteredAlerts.length > VIRTUALIZE_THRESHOLD;

    if (useVirtualization) {
      return (
        <div style={listContainerStyle}>
          <VirtualList
            items={filteredAlerts}
            itemHeight={48}
            overscan={5}
            renderItem={renderAlertItem}
          />
        </div>
      );
    }

    return (
      <div style={{ overflowY: 'auto' }}>
        {filteredAlerts.map(renderAlertItem)}
      </div>
    );
  };

  return (
    <Panel title="Alerts" actions={createAction}>
      <div data-ts-alert-manager-panel="">
        {/* Search bar */}
        {onSearchQueryChange ? (
          <div style={searchBarStyle}>
            <Input
              value={searchQuery}
              onChange={(e) => onSearchQueryChange(e.target.value)}
              placeholder="Search alerts..."
              size="sm"
              prefix={<Search size={14} />}
              data-testid="alert-search"
            />
          </div>
        ) : null}

        {/* Tabs */}
        <div style={tabBarStyle}>
          <Tabs value={activeTab} onValueChange={(v) => onTabChange(v as TabFilter)}>
            <Tabs.List>
              <Tabs.Trigger value="all">
                All<span style={countBadgeStyle}>{tabCounts.all}</span>
              </Tabs.Trigger>
              <Tabs.Trigger value="active">
                Active<span style={countBadgeStyle}>{tabCounts.active}</span>
              </Tabs.Trigger>
              <Tabs.Trigger value="triggered">
                Triggered<span style={countBadgeStyle}>{tabCounts.triggered}</span>
              </Tabs.Trigger>
              <Tabs.Trigger value="expired">
                Expired<span style={countBadgeStyle}>{tabCounts.expired}</span>
              </Tabs.Trigger>
            </Tabs.List>
          </Tabs>
        </div>

        {/* Grouping controls */}
        <div style={groupBarStyle} data-ts-alert-manager-group-selector="">
          <span style={groupLabelStyle}>Group:</span>
          {(['none', 'symbol', 'status'] as GroupBy[]).map((g) => (
            <button
              key={g}
              type="button"
              style={groupBtnStyle}
              data-active={groupBy === g ? '' : undefined}
              onClick={() => onGroupByChange(g)}
            >
              {g === 'none' ? 'None' : g === 'symbol' ? 'Symbol' : 'Status'}
            </button>
          ))}
        </div>

        {/* Content */}
        {renderContent()}
      </div>
    </Panel>
  );
}

AlertManagerPanel.displayName = 'AlertManagerPanel';
