import { useState, useEffect, useCallback, useMemo } from 'react';
import { useChannel, CHANNELS } from '@deskmodal/fdc3';
import type { StaleDataEntry } from '@deskmodal/fdc3';

/**
 * Listens to the FDC3 quality channel for stale data context updates
 * and provides a lookup for whether specific symbols have stale data.
 *
 * Returns a set of stale symbol identifiers (normalized, no slash)
 * and a helper to check individual symbols.
 */
export function useStaleSymbols(): {
  staleSymbols: ReadonlySet<string>;
  isSymbolStale: (symbol: string) => boolean;
  staleEntries: ReadonlyArray<StaleDataEntry>;
} {
  const channel = useChannel(CHANNELS.QUALITY);
  const [entries, setEntries] = useState<ReadonlyArray<StaleDataEntry>>([]);

  useEffect(() => {
    if (!channel) return;

    let cancelled = false;
    const listenerPromise = channel.addContextListener(
      'deskmodal.staleData',
      (context) => {
        if (cancelled) return;
        const staleContext = context as unknown as {
          entries?: ReadonlyArray<StaleDataEntry>;
        };
        if (staleContext.entries) {
          setEntries(staleContext.entries);
        }
      },
    );

    return () => {
      cancelled = true;
      listenerPromise.then((l) => l.unsubscribe()).catch(() => {});
    };
  }, [channel]);

  /** Build a set of normalized stale symbol names for fast lookup. */
  const staleSymbols = useMemo(() => {
    const set = new Set<string>();
    for (const entry of entries) {
      // Only flag ticker staleness for price display purposes
      if (entry.dataType === 'ticker') {
        set.add(entry.symbol.replace('/', ''));
      }
    }
    return set;
  }, [entries]);

  const isSymbolStale = useCallback(
    (symbol: string): boolean => {
      return staleSymbols.has(symbol.replace('/', ''));
    },
    [staleSymbols],
  );

  return useMemo(
    () => ({
      staleSymbols,
      isSymbolStale,
      staleEntries: entries,
    }),
    [staleSymbols, isSymbolStale, entries],
  );
}
