/**
 * FDC3 channel bridge for price and status data.
 *
 * Manages a SINGLE FDC3 channel subscription to `deskmodal.prices`
 * (and `deskmodal.status`) on behalf of all 8 apps. Consumer code
 * calls `initPriceBridge()` once and then uses `onPriceUpdate()` to
 * receive parsed PriceTick objects.
 *
 * Previously each app independently called `getOrCreateChannel()` +
 * `addContextListener()` — this module eliminates that duplication.
 */

import { updateTick, type PriceTick } from './price-store';

/* -------------------------------------------------------------------------- */
/*  Structured logging                                                         */
/* -------------------------------------------------------------------------- */

function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  if (typeof window === 'undefined') return;
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/* -------------------------------------------------------------------------- */
/*  FDC3 types (minimal, to avoid circular dep on @deskmodal/fdc3)          */
/* -------------------------------------------------------------------------- */

/** Minimal FDC3 context for type-safe parsing. */
interface FDC3Context {
  type: string;
  id?: { ticker?: string };
  [key: string]: unknown;
}

/** Minimal FDC3 Listener interface. */
interface FDC3Listener {
  unsubscribe(): void;
}

/** Minimal FDC3 Channel interface. */
interface FDC3Channel {
  addContextListener(
    contextType: string | null,
    handler: (context: FDC3Context) => void,
  ): Promise<FDC3Listener>;
}

/** Minimal DesktopAgent interface. */
interface FDC3Agent {
  getOrCreateChannel(id: string): Promise<FDC3Channel>;
}

/* -------------------------------------------------------------------------- */
/*  Price bridge                                                               */
/* -------------------------------------------------------------------------- */

const PRICES_CHANNEL = 'deskmodal.prices';

/** Whether the price bridge has been initialized. */
let priceInitialized = false;

/** Active listeners for cleanup. */
const activeListeners: FDC3Listener[] = [];

/** Price update callbacks (raw FDC3 context). */
type PriceContextCallback = (tick: PriceTick) => void;
const priceCallbacks = new Set<PriceContextCallback>();

/**
 * Parse a `deskmodal.quote` FDC3 context into a PriceTick.
 * Returns null if the context is not a valid quote.
 */
function contextToTick(context: FDC3Context): PriceTick | null {
  if (context.type === 'deskmodal.quote') {
    const ticker = context.id?.ticker;
    if (!ticker) return null;

    const last = context['last'] as number | undefined;
    const timestamp = context['timestamp'] as number | undefined;
    if (typeof last !== 'number' || typeof timestamp !== 'number') return null;

    return {
      symbol: ticker,
      exchangeId: (context['exchange'] as string | undefined) ?? 'unknown',
      last,
      bid: context['bid'] as number | undefined,
      ask: context['ask'] as number | undefined,
      spread: context['spread'] as number | undefined,
      high24h: context['high24h'] as number | undefined,
      low24h: context['low24h'] as number | undefined,
      volume24h: context['volume24h'] as number | undefined,
      quoteVolume24h: context['quoteVolume24h'] as number | undefined,
      changePercent24h: context['changePercent24h'] as number | undefined,
      bestBidQty: context['bestBidQty'] as number | undefined,
      bestAskQty: context['bestAskQty'] as number | undefined,
      timestamp,
      sequence: context['sequence'] as number | undefined,
    };
  }

  // Legacy format: fdc3.instrument with deskmodal.aggregation extension
  if (context.type === 'fdc3.instrument') {
    const ticker = context.id?.ticker;
    if (!ticker) return null;

    const agg = context['deskmodal.aggregation'] as {
      vwapPrice?: number;
      timestamp?: number;
      sources?: Array<{
        price?: number;
        volume24h?: number;
        bid?: number;
        ask?: number;
        exchange?: string;
      }>;
    } | undefined;

    if (agg?.vwapPrice !== undefined) {
      const source = agg.sources?.[0];
      const bid = source?.bid;
      const ask = source?.ask;
      return {
        symbol: ticker,
        exchangeId: source?.exchange ?? 'unknown',
        last: agg.vwapPrice,
        bid,
        ask,
        spread: bid !== undefined && ask !== undefined && ask > bid ? ask - bid : undefined,
        volume24h: agg.sources?.reduce((s, src) => s + (src.volume24h ?? 0), 0),
        timestamp: agg.timestamp ?? Date.now(),
      };
    }

    return null;
  }

  return null;
}

/**
 * Set up FDC3 channel listener for the prices channel.
 * Parses incoming contexts and pushes them into the price store.
 */
async function setupPriceListener(agent: FDC3Agent): Promise<void> {
  const channel = await agent.getOrCreateChannel(PRICES_CHANNEL);
  const listener = await channel.addContextListener(null, (context: FDC3Context) => {
    const tick = contextToTick(context);
    if (!tick) return;

    // Push into the centralized price store
    updateTick(tick);

    // Notify direct subscribers
    for (const cb of priceCallbacks) {
      try {
        cb(tick);
      } catch (err) {
        structuredLog('error', `[service-bridge] Price callback error: ${String(err)}`);
      }
    }
  });

  activeListeners.push(listener);
}

/**
 * Initialize the FDC3 price bridge with exponential backoff retry.
 */
function initWithRetry(agent: FDC3Agent): void {
  const maxRetries = 5;
  let retryCount = 0;

  function attempt(): void {
    setupPriceListener(agent).catch((err) => {
      retryCount += 1;
      structuredLog(
        'error',
        `[service-bridge] Price channel setup failed (attempt ${retryCount}/${maxRetries}): ${String(err)}`,
      );
      if (retryCount < maxRetries) {
        const delayMs = Math.min(1000 * Math.pow(2, retryCount), 30_000);
        window.setTimeout(attempt, delayMs);
      } else {
        structuredLog('error', '[service-bridge] Price channel setup failed after max retries');
        priceInitialized = false;
      }
    });
  }

  attempt();
}

/**
 * Detect FDC3 availability and initialize the price bridge.
 * Handles both cases: agent already injected, or arriving later via event.
 */
function detectAndInit(): void {
  if (typeof window === 'undefined') return;

  const win = window as { fdc3?: FDC3Agent };

  if (win.fdc3) {
    initWithRetry(win.fdc3);
    return;
  }

  function onFdc3Ready(): void {
    window.removeEventListener('fdc3Ready', onFdc3Ready);
    if (win.fdc3) {
      initWithRetry(win.fdc3);
    }
  }

  window.addEventListener('fdc3Ready', onFdc3Ready);
}

/**
 * Initialize the FDC3 price bridge. Idempotent — safe to call multiple times.
 *
 * Sets up a single FDC3 channel listener for `deskmodal.prices` and
 * forwards parsed ticks into the centralized price store. All apps share
 * this one listener instead of each creating their own.
 *
 * When FDC3 is not available (outside DeskModal), this is a no-op —
 * the price store simply stays empty and apps show "no data" gracefully.
 */
export function initPriceBridge(): void {
  if (priceInitialized) return;
  priceInitialized = true;
  detectAndInit();
}

/**
 * Subscribe to parsed price tick updates.
 * Returns an unsubscribe function.
 *
 * Each callback receives a `PriceTick` — already parsed from the FDC3
 * context. No need for the consumer to import `isDeskmodalQuote` or
 * handle legacy formats.
 */
export function onPriceUpdate(callback: PriceContextCallback): () => void {
  priceCallbacks.add(callback);
  return () => {
    priceCallbacks.delete(callback);
  };
}

/**
 * Reset bridge state. Primarily for testing.
 */
export function resetPriceBridge(): void {
  priceInitialized = false;
  priceCallbacks.clear();
  for (const listener of activeListeners) {
    try {
      listener.unsubscribe();
    } catch {
      // Ignore cleanup errors
    }
  }
  activeListeners.length = 0;
}

/* -------------------------------------------------------------------------- */
/*  Exported for testing                                                       */
/* -------------------------------------------------------------------------- */

export { contextToTick };
