import { useCallback, useRef, useState, useEffect, type CSSProperties, type KeyboardEvent } from 'react';
import { formatPrice } from '../financial/format-number';

/* -------------------------------------------------------------------------- */
/*  AggregationControl                                                         */
/*  Compact stepper + dropdown for selecting order book tick size aggregation.  */
/*  Uses --ts-aggregation-* tokens.                                            */
/* -------------------------------------------------------------------------- */

export interface AggregationControlProps {
  /** Current aggregation tick size. */
  value: number;
  /** Available tick sizes for the instrument. */
  tickSizes: number[];
  /** Called when aggregation changes. */
  onValueChange: (tickSize: number) => void;
  /** Price decimal precision (for formatting the tick size display). */
  precision?: number;
}

/* ----- Style injection --------------------------------------------------- */

const AGG_STYLE_ID = 'ts-aggregation-control-styles';

function ensureAggregationStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(AGG_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = AGG_STYLE_ID;
  sheet.textContent = `
    [data-ts-aggregation-stepper]:not(:disabled):hover {
      background: var(--ts-aggregation-stepper-bg-hover);
    }
    [data-ts-aggregation-stepper]:disabled {
      opacity: 0.35;
      cursor: not-allowed;
    }
    [data-ts-aggregation-stepper]:focus-visible,
    [data-ts-aggregation-value]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-aggregation-dropdown-item]:hover {
      background: var(--ts-aggregation-stepper-bg-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAggregationStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  height: 'var(--ts-aggregation-height)',
  border: '1px solid var(--ts-aggregation-border)',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
  background: 'var(--ts-aggregation-bg)',
  position: 'relative',
};

const stepperStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-aggregation-height)',
  height: '100%',
  background: 'var(--ts-aggregation-stepper-bg)',
  color: 'var(--ts-aggregation-text)',
  cursor: 'pointer',
  fontSize: 'var(--ts-font-md)',
  boxSizing: 'border-box',
  flexShrink: 0,
};

const valueStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  padding: '0 var(--ts-space-2)',
  minWidth: 48,
  color: 'var(--ts-aggregation-text)',
  fontFamily: 'var(--ts-aggregation-font)',
  fontSize: 'var(--ts-aggregation-font-size)',
  fontVariantNumeric: 'tabular-nums',
  cursor: 'pointer',
  userSelect: 'none',
  boxSizing: 'border-box',
};

const dropdownStyle: CSSProperties = {
  position: 'absolute',
  top: '100%',
  left: 0,
  right: 0,
  zIndex: 50,
  background: 'var(--ts-aggregation-bg)',
  border: '1px solid var(--ts-aggregation-border)',
  borderRadius: 'var(--ts-radius-sm)',
  marginTop: '2px',
  overflow: 'hidden',
  boxShadow: 'var(--ts-shadow-md)',
};

const dropdownItemStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 'var(--ts-aggregation-height)',
  color: 'var(--ts-aggregation-text)',
  fontFamily: 'var(--ts-aggregation-font)',
  fontSize: 'var(--ts-aggregation-font-size)',
  fontVariantNumeric: 'tabular-nums',
  cursor: 'pointer',
  userSelect: 'none',
};

/* ----- Component --------------------------------------------------------- */

export function AggregationControl({
  value,
  tickSizes,
  onValueChange,
  precision = 2,
}: AggregationControlProps): React.JSX.Element {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const rootRef = useRef<HTMLDivElement>(null);

  const currentIndex = tickSizes.indexOf(value);
  const isAtMin = currentIndex <= 0;
  const isAtMax = currentIndex >= tickSizes.length - 1;

  const handleDecrement = useCallback(() => {
    if (isAtMin) return;
    const prev = tickSizes[currentIndex - 1];
    if (prev !== undefined) onValueChange(prev);
  }, [isAtMin, currentIndex, tickSizes, onValueChange]);

  const handleIncrement = useCallback(() => {
    if (isAtMax) return;
    const next = tickSizes[currentIndex + 1];
    if (next !== undefined) onValueChange(next);
  }, [isAtMax, currentIndex, tickSizes, onValueChange]);

  const handleSelect = useCallback(
    (tickSize: number) => {
      onValueChange(tickSize);
      setDropdownOpen(false);
    },
    [onValueChange],
  );

  const handleValueClick = useCallback(() => {
    setDropdownOpen((prev) => !prev);
  }, []);

  const handleValueKeyDown = useCallback(
    (e: KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        setDropdownOpen((prev) => !prev);
      } else if (e.key === 'Escape') {
        setDropdownOpen(false);
      } else if (e.key === 'ArrowLeft') {
        e.preventDefault();
        handleDecrement();
      } else if (e.key === 'ArrowRight') {
        e.preventDefault();
        handleIncrement();
      }
    },
    [handleDecrement, handleIncrement],
  );

  useEffect(() => {
    if (!dropdownOpen) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (rootRef.current && !rootRef.current.contains(e.target as Node)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [dropdownOpen]);

  return (
    <div
      ref={rootRef}
      data-ts-aggregation-control=""
      style={rootStyle}
      data-testid="aggregation-control"
    >
      <button
        type="button"
        data-ts-aggregation-stepper=""
        style={stepperStyle}
        disabled={isAtMin}
        onClick={handleDecrement}
        aria-label="Decrease aggregation"
        data-testid="aggregation-decrease"
      >
        −
      </button>
      <button
        type="button"
        data-ts-aggregation-value=""
        style={valueStyle}
        onClick={handleValueClick}
        onKeyDown={handleValueKeyDown}
        aria-label={`Aggregation: ${formatPrice(value, precision)}`}
        aria-haspopup="listbox"
        aria-expanded={dropdownOpen}
        data-testid="aggregation-value"
      >
        {formatPrice(value, precision)}
      </button>
      <button
        type="button"
        data-ts-aggregation-stepper=""
        style={stepperStyle}
        disabled={isAtMax}
        onClick={handleIncrement}
        aria-label="Increase aggregation"
        data-testid="aggregation-increase"
      >
        +
      </button>
      {dropdownOpen && (
        <div
          style={dropdownStyle}
          role="listbox"
          aria-label="Available tick sizes"
          data-testid="aggregation-dropdown"
        >
          {tickSizes.map((tick) => (
            <div
              key={tick}
              role="option"
              aria-selected={tick === value}
              data-ts-aggregation-dropdown-item=""
              style={{
                ...dropdownItemStyle,
                fontWeight: tick === value ? 'var(--ts-font-weight-medium)' : 'normal',
              }}
              onClick={() => handleSelect(tick)}
              data-testid={`aggregation-option-${tick}`}
            >
              {formatPrice(tick, precision)}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

AggregationControl.displayName = 'AggregationControl';
