import { useMemo, type CSSProperties } from 'react';
import { TrendingUp, TrendingDown, Minus, ArrowUp, ArrowDown } from 'lucide-react';
import { PriceDisplay } from '../../financial';
import { PriceChange } from '../../financial';
import { Badge } from '../../primitives';
import { formatCompactNumber, formatPrice } from '../../financial';

/* -------------------------------------------------------------------------- */
/*  ScreenerCellRenderer                                                      */
/*  Factory renderer for screener table cells. Handles all cell types.        */
/*  Uses --ts-screener-cell-* tokens.                                         */
/* -------------------------------------------------------------------------- */

export type CellType =
  | 'symbol'
  | 'text'
  | 'number'
  | 'price'
  | 'change-percent'
  | 'compact-number'
  | 'sparkline'
  | 'tech-rating'
  | 'category-tags';

export interface ScreenerCellRendererProps {
  /** The cell type determining rendering behavior. */
  type: CellType;
  /** The raw value to render. */
  value: unknown;
  /** Previous value for direction comparison (price/change cells). */
  previousValue?: number;
  /** Sparkline data points (for sparkline type). */
  sparklineData?: number[];
  /** Precision for price formatting. */
  precision?: number;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-screener-cell-styles';

function ensureScreenerCellStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-screener-cell] {
      font-variant-numeric: tabular-nums slashed-zero;
      font-feature-settings: 'tnum' 1, 'zero' 1;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureScreenerCellStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const cellBaseStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  fontVariantNumeric: 'tabular-nums slashed-zero',
  fontFeatureSettings: "'tnum' 1, 'zero' 1",
  overflow: 'hidden',
  whiteSpace: 'nowrap',
  textOverflow: 'ellipsis',
};

const symbolContainerStyle: CSSProperties = {
  ...cellBaseStyle,
  gap: 'var(--ts-space-2)',
};

const symbolIconStyle: CSSProperties = {
  width: 24,
  height: 24,
  borderRadius: '50%',
  background: 'var(--ts-text-tertiary)',
  flexShrink: 0,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  fontSize: '10px',
  color: 'var(--ts-text-primary)',
  fontWeight: 'var(--ts-font-weight-bold)' as unknown as number,
  overflow: 'hidden',
};

const symbolTickerStyle: CSSProperties = {
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-primary)',
  fontSize: 'var(--ts-font-md)',
};

const symbolNameStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
  marginLeft: 'var(--ts-space-1)',
};

const numericCellStyle: CSSProperties = {
  ...cellBaseStyle,
  justifyContent: 'flex-end',
  width: '100%',
};

const textCellStyle: CSSProperties = {
  ...cellBaseStyle,
  color: 'var(--ts-text-primary)',
};

const compactUnitStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  marginLeft: '2px',
  fontSize: 'var(--ts-font-xs)',
};

const categoryTagsStyle: CSSProperties = {
  ...cellBaseStyle,
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
};

const sparklineContainerStyle: CSSProperties = {
  width: 80,
  height: 24,
  display: 'flex',
  alignItems: 'center',
};

/* ----- Tech rating helpers ----------------------------------------------- */

type TechRatingValue = 'strong-buy' | 'buy' | 'neutral' | 'sell' | 'strong-sell';

function parseTechRating(value: unknown): TechRatingValue {
  if (typeof value === 'string') {
    const normalized = value.toLowerCase().replace(/\s+/g, '-');
    if (['strong-buy', 'buy', 'neutral', 'sell', 'strong-sell'].includes(normalized)) {
      return normalized as TechRatingValue;
    }
  }
  return 'neutral';
}

const TECH_RATING_CONFIG: Record<TechRatingValue, { variant: 'success' | 'error' | 'default'; label: string; icon: typeof ArrowUp | typeof ArrowDown | typeof Minus }> = {
  'strong-buy': { variant: 'success', label: 'Strong Buy', icon: ArrowUp },
  'buy': { variant: 'success', label: 'Buy', icon: ArrowUp },
  'neutral': { variant: 'default', label: 'Neutral', icon: Minus },
  'sell': { variant: 'error', label: 'Sell', icon: ArrowDown },
  'strong-sell': { variant: 'error', label: 'Strong Sell', icon: ArrowDown },
};

/* ----- Sparkline SVG ----------------------------------------------------- */

function InlineSparkline({ data }: { data: number[] }): React.JSX.Element {
  const width = 80;
  const height = 24;
  const padding = 2;

  const points = useMemo(() => {
    if (data.length < 2) return '';
    const minVal = Math.min(...data);
    const maxVal = Math.max(...data);
    const range = maxVal - minVal || 1;
    const stepX = (width - padding * 2) / (data.length - 1);
    return data
      .map((v, i) => {
        const x = padding + i * stepX;
        const y = height - padding - ((v - minVal) / range) * (height - padding * 2);
        return `${x},${y}`;
      })
      .join(' ');
  }, [data]);

  const isPositive = data.length >= 2 && (data[data.length - 1] ?? 0) >= (data[0] ?? 0);
  const strokeColor = isPositive
    ? 'var(--ts-price-up-text, #22c55e)'
    : 'var(--ts-price-down-text, #ef4444)';

  return (
    <svg
      width={width}
      height={height}
      viewBox={`0 0 ${width} ${height}`}
      style={{ display: 'block' }}
      aria-hidden
    >
      <polyline
        points={points}
        fill="none"
        stroke={strokeColor}
        strokeWidth={1.5}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

/* ----- Component --------------------------------------------------------- */

export function ScreenerCellRenderer({
  type,
  value,
  previousValue,
  sparklineData,
  precision = 2,
}: ScreenerCellRendererProps): React.JSX.Element {
  switch (type) {
    case 'symbol': {
      const symbolVal = value as { ticker?: string; name?: string; iconUrl?: string } | string;
      const ticker = typeof symbolVal === 'string'
        ? symbolVal
        : symbolVal?.ticker ?? String(value);
      const name = typeof symbolVal === 'object' && symbolVal !== null
        ? (symbolVal as { name?: string }).name
        : undefined;
      const iconUrl = typeof symbolVal === 'object' && symbolVal !== null
        ? (symbolVal as { iconUrl?: string }).iconUrl
        : undefined;

      return (
        <div data-ts-screener-cell="" data-cell-type="symbol" style={symbolContainerStyle}>
          <div style={symbolIconStyle}>
            {iconUrl !== undefined ? (
              <img
                src={iconUrl}
                alt={ticker}
                style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }}
              />
            ) : (
              ticker.slice(0, 2).toUpperCase()
            )}
          </div>
          <span style={symbolTickerStyle}>{ticker}</span>
          {name !== undefined && <span style={symbolNameStyle}>{name}</span>}
        </div>
      );
    }

    case 'text':
      return (
        <div data-ts-screener-cell="" data-cell-type="text" style={textCellStyle}>
          {String(value ?? '')}
        </div>
      );

    case 'number':
      return (
        <div data-ts-screener-cell="" data-cell-type="number" style={numericCellStyle}>
          {formatPrice(Number(value), precision)}
        </div>
      );

    case 'price':
      return (
        <div data-ts-screener-cell="" data-cell-type="price" style={numericCellStyle}>
          <PriceDisplay
            value={Number(value)}
            previousValue={previousValue}
            precision={precision}
            size="sm"
            showFlash={false}
          />
        </div>
      );

    case 'change-percent': {
      const changeVal = Number(value);
      return (
        <div data-ts-screener-cell="" data-cell-type="change-percent" style={numericCellStyle}>
          <PriceChange
            value={changeVal}
            percentage={changeVal}
            showAbsolute={false}
            showPercentage={true}
            size="sm"
          />
        </div>
      );
    }

    case 'compact-number': {
      const numVal = Number(value);
      const formatted = formatCompactNumber(numVal);
      const numericPart = formatted.replace(/[A-Z]$/i, '');
      const unitPart = formatted.replace(/^[^A-Z]*/i, '');
      return (
        <div data-ts-screener-cell="" data-cell-type="compact-number" style={numericCellStyle}>
          <span>{numericPart}</span>
          {unitPart.length > 0 && <span style={compactUnitStyle}>{unitPart}</span>}
        </div>
      );
    }

    case 'sparkline':
      return (
        <div data-ts-screener-cell="" data-cell-type="sparkline" style={sparklineContainerStyle}>
          {sparklineData !== undefined && sparklineData.length >= 2 ? (
            <InlineSparkline data={sparklineData} />
          ) : null}
        </div>
      );

    case 'tech-rating': {
      const rating = parseTechRating(value);
      const config = TECH_RATING_CONFIG[rating];
      const Icon = config.icon;
      return (
        <div data-ts-screener-cell="" data-cell-type="tech-rating" style={cellBaseStyle}>
          <Badge variant={config.variant}>
            <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
              <Icon size={12} aria-hidden />
              {config.label}
            </span>
          </Badge>
        </div>
      );
    }

    case 'category-tags':
      return (
        <div data-ts-screener-cell="" data-cell-type="category-tags" style={categoryTagsStyle}>
          {Array.isArray(value) ? (value as string[]).join(', ') : String(value ?? '')}
        </div>
      );

    default:
      return (
        <div data-ts-screener-cell="" data-cell-type="text" style={textCellStyle}>
          {String(value ?? '')}
        </div>
      );
  }
}

ScreenerCellRenderer.displayName = 'ScreenerCellRenderer';
