/**
 * ThemeToggle — Cycles through dark / light / system themes.
 *
 * Compact button suitable for toolbar placement. Shows Sun icon in dark mode,
 * Moon icon in light mode, and Monitor icon in system mode.
 * Uses usePress from react-aria, Lucide icons, --ts-* tokens only.
 */

import { forwardRef, type CSSProperties } from 'react';
import { usePress } from '@react-aria/interactions';
import { Sun, Moon, Monitor } from 'lucide-react';
import { useTheme } from '../theme/use-theme';
import type { ThemePreference } from '../theme/theme-init';

const CYCLE_ORDER: ThemePreference[] = ['dark', 'light', 'system'];

const THEME_LABELS: Record<ThemePreference, string> = {
  dark: 'Dark theme',
  light: 'Light theme',
  system: 'System theme',
};

const THEME_ICONS: Record<ThemePreference, typeof Sun> = {
  dark: Moon,
  light: Sun,
  system: Monitor,
};

export interface ThemeToggleProps {
  /** Icon size in pixels. */
  size?: number;
}

const rootStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 28,
  height: 28,
  padding: 0,
  border: 'none',
  borderRadius: 'var(--ts-radius-sm)',
  background: 'transparent',
  color: 'var(--ts-text-secondary)',
  cursor: 'pointer',
  transition: 'background var(--ts-duration-fast) var(--ts-easing-default), color var(--ts-duration-fast) var(--ts-easing-default)',
};

const hoverStyle: CSSProperties = {
  background: 'var(--ts-button-ghost-bg-hover)',
  color: 'var(--ts-text-primary)',
};

function ensureThemeToggleStyles(): void {
  const id = 'ts-theme-toggle-styles';
  if (document.getElementById(id)) return;
  const style = document.createElement('style');
  style.id = id;
  style.textContent = `
    [data-ts-theme-toggle]:hover,
    [data-ts-theme-toggle]:focus-visible {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-text-primary);
    }
  `;
  document.head.appendChild(style);
}

export const ThemeToggle = forwardRef<HTMLButtonElement, ThemeToggleProps>(
  function ThemeToggle({ size = 14 }, ref) {
    ensureThemeToggleStyles();

    const { theme, setTheme } = useTheme();

    const nextTheme = CYCLE_ORDER[(CYCLE_ORDER.indexOf(theme) + 1) % CYCLE_ORDER.length]!;
    const label = `${THEME_LABELS[theme]} (click for ${THEME_LABELS[nextTheme].toLowerCase()})`;
    const Icon = THEME_ICONS[theme];

    const { pressProps } = usePress({
      onPress: () => {
        setTheme(nextTheme);
      },
    });

    return (
      <button
        {...pressProps}
        ref={ref}
        type="button"
        data-ts-theme-toggle=""
        aria-label={label}
        title={label}
        style={rootStyle}
      >
        <Icon size={size} />
      </button>
    );
  },
);
