import { useMemo } from 'react';
import { useKeyboardShortcuts, type KeyboardShortcutMap } from '@deskmodal/core';
import { useDeskModalShortcuts } from '@deskmodal/fdc3';

/* -------------------------------------------------------------------------- */
/*  useWatchlistKeyboard                                                       */
/*  Registers watchlist-specific keyboard shortcuts.                           */
/*  Ctrl+K      -> Open symbol search                                          */
/*  Ctrl+F      -> Focus filter input                                          */
/*  Arrow Up    -> Navigate rows up                                            */
/*  Arrow Down  -> Navigate rows down                                          */
/*  Enter       -> Select highlighted row                                      */
/* -------------------------------------------------------------------------- */

export interface WatchlistKeyboardActions {
  onOpenSymbolSearch: () => void;
  onFocusFilter: () => void;
  onNavigateUp: () => void;
  onNavigateDown: () => void;
  onSelectRow: () => void;
}

export function useWatchlistKeyboard(actions: WatchlistKeyboardActions): void {
  const shortcuts = useMemo<KeyboardShortcutMap>(
    () => ({
      'Ctrl+K': actions.onOpenSymbolSearch,
      'Ctrl+F': actions.onFocusFilter,
      'ArrowUp': actions.onNavigateUp,
      'ArrowDown': actions.onNavigateDown,
      'Enter': actions.onSelectRow,
    }),
    [
      actions.onOpenSymbolSearch,
      actions.onFocusFilter,
      actions.onNavigateUp,
      actions.onNavigateDown,
      actions.onSelectRow,
    ],
  );

  useDeskModalShortcuts('watchlist', shortcuts);
  useKeyboardShortcuts(shortcuts);
}
