/**
 * Cross-app drag-drop context type for DeskModal.
 *
 * FDC3 2.2 does not define a drag-drop standard. This is a DeskModal extension
 * (`deskmodal.dragDrop`) that wraps any FDC3 context with drag metadata. The
 * shell orchestrates the drag lifecycle via the WCP postMessage bridge — source
 * iframes emit `dragStart`/`dragEnd`, the shell tracks cursor position across
 * iframe boundaries, and target iframes receive `dragEnter`/`dragLeave`/`drop`
 * events with the wrapped context.
 *
 * FDC3 fallback: when the DeskModal drag extension is unavailable, apps use
 * `fdc3.raiseIntent()` via context menu "Send to..." as an equivalent workflow.
 */

import type { Context } from "../fdc3-types";

/** Phases of the cross-app drag lifecycle. */
export type DragDropPhase =
  | "start"
  | "move"
  | "enter"
  | "leave"
  | "drop"
  | "cancel";

/** The operation type for the drag. */
export type DragOperation = "link" | "copy";

/**
 * Context wrapper for cross-app drag-drop. The `innerContext` field carries
 * the actual FDC3 context being transferred (typically `fdc3.instrument`).
 */
export interface DragDropContext extends Context {
  type: "deskmodal.dragDrop";
  /** The FDC3 context being dragged (e.g., fdc3.instrument). */
  innerContext: Context;
  /** Source app identifier. Set by the shell on drag start. */
  sourceAppId?: string;
  /** Source instance identifier. Set by the shell on drag start. */
  sourceInstanceId?: string;
  /** Drag operation type. Defaults to "link" (send context to target). */
  operation: DragOperation;
}

/** PostMessage payload sent from source iframe to shell on drag initiation. */
export interface DragStartMessage {
  type: "deskmodal:dragStart";
  payload: {
    context: DragDropContext;
    /** Cursor position relative to the source iframe viewport. */
    cursorX: number;
    cursorY: number;
  };
}

/** PostMessage payload sent from source iframe for cursor tracking. */
export interface DragMoveMessage {
  type: "deskmodal:dragMove";
  payload: {
    /** Cursor position relative to the source iframe viewport. */
    cursorX: number;
    cursorY: number;
  };
}

/** PostMessage payload sent from source iframe to cancel/end the drag. */
export interface DragEndMessage {
  type: "deskmodal:dragEnd";
  payload: {
    cancelled: boolean;
  };
}

/** PostMessage payload sent from shell to target iframe. */
export interface DragEventMessage {
  type: "deskmodal:dragEvent";
  payload: {
    phase: DragDropPhase;
    context: DragDropContext;
  };
}

/** Union of all drag-related postMessage types. */
export type DragMessage =
  | DragStartMessage
  | DragMoveMessage
  | DragEndMessage
  | DragEventMessage;

/** Create a DragDropContext wrapping an inner FDC3 context. */
export function createDragDropContext(
  innerContext: Context,
  operation: DragOperation = "link",
): DragDropContext {
  return {
    type: "deskmodal.dragDrop",
    name: innerContext.name,
    innerContext,
    operation,
  };
}

/** Type guard for DragDropContext. */
export function isDragDropContext(ctx: Context): ctx is DragDropContext {
  return ctx.type === "deskmodal.dragDrop" && "innerContext" in ctx;
}

/** Type guard for drag-related postMessage events. */
export function isDragMessage(data: unknown): data is DragMessage {
  if (typeof data !== "object" || data === null) return false;
  const msg = data as { type?: string };
  return (
    msg.type === "deskmodal:dragStart" ||
    msg.type === "deskmodal:dragMove" ||
    msg.type === "deskmodal:dragEnd" ||
    msg.type === "deskmodal:dragEvent"
  );
}
