import { useState, useCallback, useMemo, useEffect, useRef, type CSSProperties } from 'react';
import '@deskmodal/ui-components/tokens/brand.css';
import '@deskmodal/ui-components/tokens/brand-light.css';
import '@deskmodal/ui-components/tokens/deskmodal-bridge.css';
import '@deskmodal/ui-components/tokens/components.css';
import '@deskmodal/ui-components/tokens/components-light.css';
import {
  AppShell,
  AppHeader,
  WatchlistPanel,
  ErrorBoundary,
  SymbolSearchDialog,
  IconButton,
  Toaster,
  toast,
  type WatchlistColumn,
  type HotlistCategory,
  type SymbolSearchResult,
  type AssetTypeFilter,
} from '@deskmodal/ui-components';
import { useStateResetNotification } from '../../shared/hooks/use-state-reset-notification';
import { List, Settings2 } from 'lucide-react';
import { useFdc3, INTENTS, useCrossAppDragSource, useDeskModalStorage } from '@deskmodal/fdc3';
import type { CryptoInstrumentContext } from '@deskmodal/fdc3';
import { createInstrumentContext } from '@deskmodal/fdc3';
import { useSessionPersistence } from '../../shared/hooks/use-session-persistence';
import { COLUMNS } from './watchlist-constants';
import { type ViewMode, VIEW_MODE_COLUMNS, VIEW_MODE_LABELS } from './view-modes';
import { useFdc3Broadcast } from './hooks/use-fdc3-broadcast';
import { useWatchlistData } from './hooks/use-watchlist-data';
import { useWatchlistStore } from './store/watchlist-store';
import { usePriceAnnouncer } from './hooks/use-price-announcer';
import { useStaleSymbols } from './hooks/use-stale-symbols';
import { useViewQuoteIntent } from './hooks/use-view-quote-intent';
import { useWatchlistKeyboard } from './hooks/use-watchlist-keyboard';
import { useSubscriptionManager } from './hooks/use-subscription-manager';
import { SubscriptionManagerDialog } from './components/SubscriptionManagerDialog';
import { useSparklineHistory } from './hooks/use-sparkline-history';

/* -------------------------------------------------------------------------- */
/*  Styles                                                                    */
/* -------------------------------------------------------------------------- */

const WATCHLIST_VIEW_MODES = (Object.keys(VIEW_MODE_LABELS) as ViewMode[]).map((id) => ({
  id,
  label: VIEW_MODE_LABELS[id],
}));

type ViewTab = 'all' | 'gainers' | 'losers' | 'volume' | 'new';

const VIEW_TABS: { id: ViewTab; label: string }[] = [
  { id: 'all', label: 'All' },
  { id: 'gainers', label: 'Gainers' },
  { id: 'losers', label: 'Losers' },
  { id: 'volume', label: 'Volume' },
  { id: 'new', label: 'New' },
];

const contentStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  overflow: 'hidden',
};

const tabBarStyle: CSSProperties = {
  display: 'flex',
  gap: '1px',
  padding: '0 var(--ts-space-2, 8px)',
  background: 'var(--ts-panel-border, #1e1e2e)',
  flexShrink: 0,
  overflow: 'hidden',
};

const tabBtnBase: CSSProperties = {
  padding: '4px 10px',
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 500,
  border: 'none',
  cursor: 'pointer',
  textTransform: 'uppercase',
  letterSpacing: '0.04em',
  transition: 'background 100ms, color 100ms',
};

const tabBtnDefault: CSSProperties = {
  ...tabBtnBase,
  background: 'transparent',
  color: 'var(--ts-text-secondary, #9ca3af)',
};

const tabBtnActive: CSSProperties = {
  ...tabBtnBase,
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  color: 'var(--ts-text-primary, #e5e7eb)',
  borderBottom: '2px solid var(--ts-accent-default, #3b82f6)',
};

/* -------------------------------------------------------------------------- */
/*  App                                                                       */
/* -------------------------------------------------------------------------- */

/**
 * Extract the raw ticker from a watchlist symbol ID (format "EXCHANGE:TICKER").
 * Returns the ticker portion, or the original string if no colon is found.
 */
function extractTicker(symbolId: string): string {
  const colonIdx = symbolId.indexOf(':');
  return colonIdx === -1 ? symbolId : symbolId.slice(colonIdx + 1);
}

export function App(): React.JSX.Element {
  useStateResetNotification((msg) => toast.info({ title: msg, duration: 3000 }));

  const { sections: rawSections, setSections, hotlistSymbols } = useWatchlistData();
  const broadcastInstrument = useFdc3Broadcast();
  const priceAnnouncerRef = usePriceAnnouncer();
  const { isSymbolStale } = useStaleSymbols();
  const { targetTicker, clearTarget } = useViewQuoteIntent();
  useSparklineHistory();
  const fdc3 = useFdc3();

  // Auto-join first user channel so FDC3 broadcasts work in modal windows
  useEffect(() => {
    if (!fdc3) return;
    fdc3.getUserChannels().then((channels) => {
      if (channels && channels.length > 0) {
        fdc3.joinUserChannel(channels[0].id).catch(() => {});
      }
    }).catch(() => {});
  }, [fdc3]);
  const removeSymbolFromStore = useWatchlistStore((s) => s.removeSymbol);

  const addSymbolToStore = useWatchlistStore((s) => s.addSymbol);

  const {
    subscribe: handleFeedSubscribe,
    unsubscribe: handleFeedUnsubscribe,
    subscriptions: feedSubscriptions,
    getByExchange,
  } = useSubscriptionManager();

  const [selectedSymbolId, setSelectedSymbolId] = useState<string | undefined>(undefined);
  const [symbolSearchOpen, setSymbolSearchOpen] = useState(false);
  const [subscriptionManagerOpen, setSubscriptionManagerOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [symbolSearchQuery, setSymbolSearchQuery] = useState('');
  const [symbolSearchFilter, setSymbolSearchFilter] = useState<AssetTypeFilter>('all');

  /* --- View mode state (persisted) --- */
  const [viewMode, setViewMode] = useState<ViewMode>(() =>
    (localStorage.getItem('deskmodal:watchlist:viewMode') as ViewMode) || 'price',
  );

  useEffect(() => {
    localStorage.setItem('deskmodal:watchlist:viewMode', viewMode);
  }, [viewMode]);

  /* --- Keyboard shortcuts --- */
  useWatchlistKeyboard({
    onOpenSymbolSearch: useCallback(() => setSymbolSearchOpen(true), []),
    onFocusFilter: useCallback(() => {
      const input = document.querySelector<HTMLInputElement>('[data-ts-input-field]');
      input?.focus();
    }, []),
    onNavigateUp: useCallback(() => {
      const allSymbols = rawSections.flatMap((s) => s.symbols);
      if (allSymbols.length === 0) return;
      const currentIdx = allSymbols.findIndex((s) => s.id === selectedSymbolId);
      const nextIdx = currentIdx > 0 ? currentIdx - 1 : allSymbols.length - 1;
      const nextSymbol = allSymbols[nextIdx];
      if (nextSymbol !== undefined) {
        setSelectedSymbolId(nextSymbol.id);
      }
    }, [selectedSymbolId, rawSections]),
    onNavigateDown: useCallback(() => {
      const allSymbols = rawSections.flatMap((s) => s.symbols);
      if (allSymbols.length === 0) return;
      const currentIdx = allSymbols.findIndex((s) => s.id === selectedSymbolId);
      const nextIdx = currentIdx < allSymbols.length - 1 ? currentIdx + 1 : 0;
      const nextSymbol = allSymbols[nextIdx];
      if (nextSymbol !== undefined) {
        setSelectedSymbolId(nextSymbol.id);
      }
    }, [selectedSymbolId, rawSections]),
    onSelectRow: useCallback(() => {
      if (selectedSymbolId !== undefined) {
        broadcastInstrument(selectedSymbolId);
      }
    }, [selectedSymbolId, broadcastInstrument]),
  });

  /* --- Type-ahead: alphanumeric keystrokes open symbol search with typed chars --- */
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      // Ignore when focus is in an input, dialog, or when modifiers are held
      const target = e.target as HTMLElement;
      if (
        target.tagName === 'INPUT' ||
        target.tagName === 'TEXTAREA' ||
        target.isContentEditable ||
        e.ctrlKey || e.metaKey || e.altKey
      ) return;

      // Only capture single alphanumeric characters
      if (e.key.length === 1 && /[a-zA-Z0-9]/.test(e.key)) {
        e.preventDefault();
        setSymbolSearchQuery(e.key.toUpperCase());
        setSymbolSearchOpen(true);
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  /* ----- Handle incoming ViewQuote intent: scroll to / highlight symbol --- */
  useEffect(() => {
    if (!targetTicker) return;

    // Find the symbol ID in sections matching the target ticker
    for (const section of rawSections) {
      const match = section.symbols.find((s) => s.symbol === targetTicker);
      if (match) {
        setSelectedSymbolId(match.id);
        break;
      }
    }

    clearTarget();
  }, [targetTicker, clearTarget, rawSections]);
  // Build a deduplicated superset of ALL columns across all view modes + COLUMNS,
  // so that resizing any column (regardless of active view mode) is tracked.
  const [allColumns, setAllColumns] = useState<WatchlistColumn[]>(() => {
    const seen = new Set<string>();
    const merged: WatchlistColumn[] = [];
    // Start with the base COLUMNS definitions
    for (const col of COLUMNS) {
      if (!seen.has(col.id)) {
        seen.add(col.id);
        merged.push(col);
      }
    }
    // Add any columns from view modes that aren't in COLUMNS
    for (const modeCols of Object.values(VIEW_MODE_COLUMNS)) {
      for (const col of modeCols) {
        if (!seen.has(col.id)) {
          seen.add(col.id);
          merged.push(col);
        }
      }
    }
    return merged;
  });
  const [containerWidth, setContainerWidth] = useState(800);
  const containerRef = useRef<HTMLDivElement>(null);

  // Persist column widths via DeskModal storage (falls back to localStorage)
  const storage = useDeskModalStorage('deskmodal.watchlist');
  const columnWidthsLoaded = useRef(false);

  // Load saved column widths on mount
  useEffect(() => {
    if (columnWidthsLoaded.current) return;
    columnWidthsLoaded.current = true;
    storage.get('columnWidths').then((saved) => {
      if (!saved) return;
      try {
        const widths = JSON.parse(saved) as Record<string, number>;
        setAllColumns((prev) =>
          prev.map((col) => {
            const savedWidth = widths[col.id];
            return savedWidth != null ? { ...col, width: savedWidth } : col;
          }),
        );
      } catch {
        // Corrupt data — ignore
      }
    }).catch(() => {});
  }, [storage]);

  // Save column widths when they change (debounced via timeout)
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  useEffect(() => {
    if (!columnWidthsLoaded.current) return;
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => {
      const widths: Record<string, number> = {};
      for (const col of allColumns) {
        if (typeof col.width === 'number') {
          widths[col.id] = col.width;
        }
      }
      storage.set('columnWidths', JSON.stringify(widths)).catch(() => {});
    }, 500);
    return () => {
      if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    };
  }, [allColumns, storage]);

  // Derive base columns from the active view mode, merging in any user-resized widths.
  // Width overrides apply to ANY column (including flex), so dragging a resize handle
  // always takes effect regardless of the column's default width type.
  const baseColumns = useMemo(
    (): WatchlistColumn[] => {
      const modeColumns = VIEW_MODE_COLUMNS[viewMode];
      // Build a width override map from allColumns (which tracks user resizes)
      const widthOverrides = new Map<string, number>();
      for (const col of allColumns) {
        if (typeof col.width === 'number') {
          widthOverrides.set(col.id, col.width);
        }
      }
      return modeColumns.map((col) => {
        const overrideWidth = widthOverrides.get(col.id);
        if (overrideWidth != null) {
          return { ...col, width: overrideWidth };
        }
        return col;
      });
    },
    [viewMode, allColumns],
  );

  // Responsive columns — hide low-priority columns when panel is narrow.
  // Priority varies by view mode; core columns are always preserved.
  const columns = useMemo((): WatchlistColumn[] => {
    if (containerWidth >= 700) return baseColumns;
    if (containerWidth >= 500) {
      // Medium: keep up to 6 most important columns per view mode
      const mediumKeep: Record<ViewMode, string[]> = {
        price: ['symbol', 'price', 'change', 'bid', 'offer', 'volume'],
        performance: ['symbol', 'change1h', 'change', 'change7d', 'volume', 'sparkline'],
        technicals: ['symbol', 'price', 'rsi', 'macdSignal', 'volume', 'fundingRate'],
      };
      const keep = mediumKeep[viewMode] ?? mediumKeep.price;
      return baseColumns.filter((c) => keep.includes(c.id));
    }
    // Narrow: symbol + 2 key data columns per view mode
    const narrowKeep: Record<ViewMode, string[]> = {
      price: ['symbol', 'price', 'change'],
      performance: ['symbol', 'change', 'change7d'],
      technicals: ['symbol', 'price', 'rsi'],
    };
    const keep = narrowKeep[viewMode] ?? narrowKeep.price;
    return baseColumns.filter((c) => keep.includes(c.id));
  }, [baseColumns, containerWidth, viewMode]);

  // Track container width for responsive column visibility
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerWidth(entry.contentRect.width);
      }
    });
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  // Handle column resize by updating the column width in allColumns.
  // If the column isn't tracked yet (shouldn't happen, but defensive), append it.
  const handleColumnResize = useCallback(
    (columnId: string, newWidth: number) => {
      const rounded = Math.round(newWidth);
      setAllColumns((prev) => {
        const exists = prev.some((col) => col.id === columnId);
        if (exists) {
          return prev.map((col) =>
            col.id === columnId
              ? { ...col, width: Math.max(rounded, col.minWidth ?? 40) }
              : col,
          );
        }
        // Column not tracked — append it with the resized width
        return [...prev, { id: columnId, label: columnId, width: Math.max(rounded, 40), align: 'right' as const }];
      });
    },
    [],
  );

  const [sortColumn, setSortColumn] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');
  const [activeTab, setActiveTab] = useState<ViewTab>('all');

  // Session persistence for dock/undock state survival
  useSessionPersistence(
    'deskmodal:watchlist:session',
    1,
    { sortColumn, sortDirection, activeTab },
    (saved) => {
      if (saved.sortColumn !== undefined) setSortColumn(saved.sortColumn as string | null);
      if (saved.sortDirection) setSortDirection(saved.sortDirection as 'asc' | 'desc');
      if (saved.activeTab) setActiveTab(saved.activeTab as ViewTab);
    },
    [sortColumn, sortDirection, activeTab],
  );

  /* --- Action handlers --- */

  const handleViewChart = useCallback(
    (symbolId: string) => {
      const ticker = extractTicker(symbolId);
      if (!fdc3) return;
      const ctx: CryptoInstrumentContext = {
        type: 'fdc3.instrument',
        name: ticker,
        id: { ticker },
      };
      // Broadcast on channel so linked apps (chart, depth, etc.) update
      fdc3.broadcast(ctx as never).catch(() => {});
      // Also raise intent for explicit chart focus
      fdc3.raiseIntent(INTENTS.ViewChart, ctx).catch(() => {});
    },
    [fdc3],
  );

  const handleAddAlert = useCallback(
    (symbolId: string) => {
      const ticker = extractTicker(symbolId);
      if (!fdc3) return;
      const ctx: CryptoInstrumentContext = {
        type: 'fdc3.instrument',
        name: ticker,
        id: { ticker },
      };
      fdc3.raiseIntent(INTENTS.CreateAlert, ctx).catch(() => {
        // Intent delivery failure is non-critical
      });
    },
    [fdc3],
  );

  const handleViewDepth = useCallback(
    (symbolId: string) => {
      const ticker = extractTicker(symbolId);
      if (!fdc3) return;
      const ctx: CryptoInstrumentContext = {
        type: 'fdc3.instrument',
        name: ticker,
        id: { ticker },
      };
      fdc3.raiseIntent(INTENTS.ViewDepth, ctx).catch(() => {
        // Intent delivery failure is non-critical
      });
    },
    [fdc3],
  );

  // Cross-app drag-drop: drag a symbol from watchlist to chart/depth/analytics tile
  const { startDrag: startCrossAppDrag } = useCrossAppDragSource();
  const handleCrossAppDragStart = useCallback(
    (symbolId: string, event: React.MouseEvent) => {
      const ticker = extractTicker(symbolId);
      const ctx: CryptoInstrumentContext = {
        type: 'fdc3.instrument',
        name: ticker,
        id: { ticker },
      };
      startCrossAppDrag(ctx, event);
    },
    [startCrossAppDrag],
  );

  // FDC3 intent: send to analytics
  const handleSendToAnalytics = useCallback(
    (symbolId: string) => {
      const ticker = extractTicker(symbolId);
      if (!fdc3) return;
      const ctx: CryptoInstrumentContext = { type: 'fdc3.instrument', name: ticker, id: { ticker } };
      fdc3.raiseIntent(INTENTS.ViewAnalysis, ctx).catch(() => {});
    },
    [fdc3],
  );

  // FDC3 intent: send to screener
  const handleSendToScreener = useCallback(
    (symbolId: string) => {
      const ticker = extractTicker(symbolId);
      if (!fdc3) return;
      const ctx: CryptoInstrumentContext = { type: 'fdc3.instrument', name: ticker, id: { ticker } };
      fdc3.raiseIntent(INTENTS.ViewQuote, ctx).catch(() => {});
    },
    [fdc3],
  );

  const handleRemoveSymbol = useCallback(
    (symbolId: string) => {
      const ticker = extractTicker(symbolId);
      removeSymbolFromStore(ticker);
    },
    [removeSymbolFromStore],
  );

  const handleAddSymbol = useCallback(() => {
    setSymbolSearchOpen(true);
  }, []);

  const handleSearch = useCallback(() => {
    setSymbolSearchOpen(true);
  }, []);

  /** Handle symbol selection from the search dialog. */
  const handleSearchSymbolSelect = useCallback(
    (result: SymbolSearchResult) => {
      addSymbolToStore(result.symbol);
      setSymbolSearchOpen(false);
      setSymbolSearchQuery('');
    },
    [addSymbolToStore],
  );

  /** Build search results from the current watchlist store symbols. */
  const symbolSearchResults = useMemo((): SymbolSearchResult[] => {
    const { symbols } = useWatchlistStore.getState();
    const query = symbolSearchQuery.trim().toUpperCase();
    if (query.length === 0) return [];
    return symbols
      .filter((sym) => sym.toUpperCase().includes(query))
      .map((sym) => ({
        symbol: sym,
        description: sym,
        exchange: 'Binance',
        assetType: 'crypto' as const,
      }));
  }, [symbolSearchQuery]);

  const handleSymbolSelect = useCallback(
    (symbolId: string) => {
      setSelectedSymbolId(symbolId);
      broadcastInstrument(symbolId);
    },
    [broadcastInstrument],
  );

  const handleSortChange = useCallback((columnId: string) => {
    setSortColumn((prev) => {
      if (prev === columnId) {
        setSortDirection((d) => (d === 'asc' ? 'desc' : 'asc'));
        return columnId;
      }
      setSortDirection('desc');
      return columnId;
    });
  }, []);

  const handleSectionToggle = useCallback((sectionId: string) => {
    setSections((prev) =>
      prev.map((s) =>
        s.id === sectionId ? { ...s, collapsed: !s.collapsed } : s,
      ),
    );
  }, [setSections]);

  const handleSymbolReorder = useCallback(
    (symbolId: string, targetSectionId: string, targetIndex: number) => {
      setSections((prev) => {
        let movedSymbol = null;
        const withoutSymbol = prev.map((section) => {
          const idx = section.symbols.findIndex((s) => s.id === symbolId);
          if (idx === -1) return section;
          movedSymbol = section.symbols[idx];
          return {
            ...section,
            symbols: [...section.symbols.slice(0, idx), ...section.symbols.slice(idx + 1)],
          };
        });
        if (!movedSymbol) return prev;
        return withoutSymbol.map((section) => {
          if (section.id !== targetSectionId) return section;
          const newSymbols = [...section.symbols];
          newSymbols.splice(targetIndex, 0, movedSymbol!);
          return { ...section, symbols: newSymbols };
        });
      });
    },
    [setSections],
  );

  /** Build display sections — either full watchlist or hotlist-filtered view. */
  const sections = useMemo(
    () => {
      const query = searchQuery.trim().toUpperCase();
      const decorateSections = (secs: typeof rawSections) =>
        secs.map((section) => ({
          ...section,
          symbols: section.symbols
            .filter((sym) => query === '' || sym.symbol.toUpperCase().includes(query))
            .map((sym) => ({
              ...sym,
              stale: isSymbolStale(sym.symbol),
            })),
        }));

      if (activeTab === 'all') {
        return decorateSections(rawSections);
      }

      // Hotlist category view — sort/filter all symbols into a single section
      const hotSymbols = hotlistSymbols(activeTab as HotlistCategory);
      return [{
        id: activeTab,
        label: activeTab.charAt(0).toUpperCase() + activeTab.slice(1),
        collapsed: false,
        symbols: hotSymbols
          .filter((sym) => query === '' || sym.symbol.toUpperCase().includes(query))
          .map((sym) => ({
            ...sym,
            stale: isSymbolStale(sym.symbol),
          })),
      }];
    },
    [rawSections, isSymbolStale, searchQuery, activeTab, hotlistSymbols],
  );

  return (
    <ErrorBoundary level="app">
    <AppShell
      header={
        <AppHeader
          title="Watchlist"
          icon={<List size={16} />}
          actions={
            <IconButton
              icon={<Settings2 size={14} />}
              label="Manage subscriptions"
              onClick={() => setSubscriptionManagerOpen(true)}
              size="sm"
            />
          }
        />
      }
    >
      {/* ARIA live region for screen reader price announcements (polite, 1s debounce) */}
      <div
        ref={priceAnnouncerRef}
        aria-live="polite"
        role="status"
        style={{ position: 'absolute', width: 1, height: 1, overflow: 'hidden', clip: 'rect(0,0,0,0)' }}
      />
      <div ref={containerRef} style={contentStyle}>
        <WatchlistPanel
          sections={sections}
          selectedSymbolId={selectedSymbolId}
          columns={columns}
          sortColumn={sortColumn}
          sortDirection={sortDirection}
          densityMode="compact"
          viewMode={viewMode}
          containerWidth={containerWidth}
          onViewModeChange={setViewMode as (mode: string) => void}
          viewModes={WATCHLIST_VIEW_MODES}
          onSymbolSelect={handleSymbolSelect}
          onSortChange={handleSortChange}
          onSectionToggle={handleSectionToggle}
          onSymbolReorder={handleSymbolReorder}
          onColumnsChange={setAllColumns}
          onColumnResize={handleColumnResize}
          onViewChart={handleViewChart}
          onAddAlert={handleAddAlert}
          onViewDepth={handleViewDepth}
          onRemoveSymbol={handleRemoveSymbol}
          onAddSymbol={handleAddSymbol}
          onSearch={handleSearch}
          onCrossAppDragStart={handleCrossAppDragStart}
          onSendToAnalytics={handleSendToAnalytics}
          onSendToScreener={handleSendToScreener}
        />
      </div>
      <SymbolSearchDialog
        open={symbolSearchOpen}
        onOpenChange={setSymbolSearchOpen}
        onSymbolSelect={handleSearchSymbolSelect}
        results={symbolSearchResults}
        query={symbolSearchQuery}
        onQueryChange={setSymbolSearchQuery}
        assetFilter={symbolSearchFilter}
        onAssetFilterChange={setSymbolSearchFilter}
      />
      <SubscriptionManagerDialog
        open={subscriptionManagerOpen}
        onOpenChange={setSubscriptionManagerOpen}
        subscriptions={feedSubscriptions}
        onSubscribe={handleFeedSubscribe}
        onUnsubscribe={handleFeedUnsubscribe}
        getByExchange={getByExchange}
      />
      <Toaster position="bottom-right" theme="dark" />
    </AppShell>
    </ErrorBoundary>
  );
}
