import { useEffect, useRef } from "react";
import { getDeskModalAPI } from "../desk/desk-detection";

/**
 * Map of key combination strings to handler functions.
 * Re-defined here to avoid a cross-package dependency on @deskmodal/core.
 */
export type KeyboardShortcutMap = Readonly<Record<string, () => void>>;

/**
 * Hook that registers keyboard shortcuts with the DeskModal Desktop Agent
 * for system-wide shortcut management.
 *
 * When running on DeskModal, shortcuts are registered via the `shortcuts` API
 * on mount and unregistered on unmount. This enables DeskModal to show shortcuts
 * in its global shortcut viewer and handle cross-app shortcut conflicts.
 *
 * This hook does NOT handle local keyboard event listening — callers should
 * continue to use `useKeyboardShortcuts` from `@deskmodal/core` for local
 * event handling. This hook purely bridges shortcut metadata to DeskModal.
 *
 * @param appId   Application identifier for shortcut scoping (e.g., 'chart').
 * @param shortcuts  Map of key combination strings to handler functions.
 */
export function useDeskModalShortcuts(
  appId: string,
  shortcuts: KeyboardShortcutMap,
): void {
  const shortcutsRef = useRef(shortcuts);
  shortcutsRef.current = shortcuts;

  // Track which keys were registered so we can unregister them on cleanup
  const registeredKeysRef = useRef<string[]>([]);

  useEffect(() => {
    const api = getDeskModalAPI();
    if (!api?.shortcuts) {
      return;
    }

    const keys = Object.keys(shortcuts);
    const registrationPromises: Promise<void>[] = [];

    for (const key of keys) {
      registrationPromises.push(
        api.shortcuts
          .register(appId, key, key, "AppFocused")
          .catch(() => {
            // Registration failure — degrade silently
          }),
      );
    }

    registeredKeysRef.current = keys;

    return () => {
      const registeredKeys = registeredKeysRef.current;
      const currentApi = getDeskModalAPI();
      if (!currentApi?.shortcuts) return;

      for (const key of registeredKeys) {
        currentApi.shortcuts.unregister(appId, key).catch(() => {
          // Unregistration failure — degrade silently
        });
      }
      registeredKeysRef.current = [];
    };
    // Re-register when the set of shortcut keys changes
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [appId, Object.keys(shortcuts).sort().join(",")]);
}
