import { useEffect, useRef, useMemo } from 'react';
import { parseKeyCombo } from './keyboard-manager';
import type { ParsedKeyCombo } from './keyboard-shortcuts';

/* -------------------------------------------------------------------------- */
/*  useKeyboardShortcuts                                                       */
/*  React hook that registers keyboard shortcut handlers on the document.     */
/*  Accepts a map of key combinations to handler functions.                   */
/*  Automatically cleans up on unmount or when shortcuts change.              */
/* -------------------------------------------------------------------------- */

/**
 * Map of key combination strings to handler functions.
 * Key format matches KeyboardShortcut.keys (e.g., "Ctrl+K", "Escape", "/").
 */
export type KeyboardShortcutMap = Readonly<Record<string, () => void>>;

interface ShortcutEntry {
  combo: ParsedKeyCombo;
  handler: () => void;
}

/**
 * Determine if a keyboard event matches a pre-parsed key combination.
 */
function matchesParsedCombo(event: KeyboardEvent, combo: ParsedKeyCombo): boolean {
  if (event.ctrlKey !== combo.ctrl) return false;
  if (event.shiftKey !== combo.shift) return false;
  if (event.altKey !== combo.alt) return false;
  if (event.metaKey !== combo.meta) return false;
  return event.key.toLowerCase() === combo.key;
}

/**
 * Check whether an event target is an input, textarea, or contenteditable element.
 */
function isInputElement(target: EventTarget | null): boolean {
  if (target === null) return false;
  if (!(target instanceof HTMLElement)) return false;
  const tag = target.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
  return target.isContentEditable;
}

/**
 * Register keyboard shortcuts that fire handler functions when their
 * key combinations are pressed. Handles input element awareness:
 * shortcuts with modifiers (Ctrl, Alt, Meta) fire even in inputs,
 * while plain key shortcuts (e.g., "/", "Escape") only fire outside inputs.
 *
 * @param shortcuts Map of key combination strings to handler functions.
 */
export function useKeyboardShortcuts(shortcuts: KeyboardShortcutMap): void {
  // Keep a stable reference to the latest shortcuts to avoid re-attaching
  const shortcutsRef = useRef(shortcuts);
  shortcutsRef.current = shortcuts;

  // Parse combos once when the keys change
  const entries = useMemo<ShortcutEntry[]>(() => {
    return Object.entries(shortcuts).map(([keys, handler]) => ({
      combo: parseKeyCombo(keys),
      handler,
    }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    // Re-parse when the set of keys changes
    Object.keys(shortcuts).sort().join(','),
  ]);

  useEffect(() => {
    function handleKeyDown(event: KeyboardEvent): void {
      const inInput = isInputElement(event.target);

      for (const entry of entries) {
        if (matchesParsedCombo(event, entry.combo)) {
          // For plain key shortcuts (no modifiers), skip if user is in an input
          const hasModifier = entry.combo.ctrl || entry.combo.alt || entry.combo.meta;
          if (!hasModifier && inInput) continue;

          event.preventDefault();
          event.stopPropagation();
          // Call the latest handler from ref to avoid stale closures
          const currentHandler = shortcutsRef.current[
            Object.keys(shortcutsRef.current).find((key) => {
              const parsed = parseKeyCombo(key);
              return (
                parsed.key === entry.combo.key &&
                parsed.ctrl === entry.combo.ctrl &&
                parsed.shift === entry.combo.shift &&
                parsed.alt === entry.combo.alt &&
                parsed.meta === entry.combo.meta
              );
            }) ?? ''
          ];
          currentHandler?.();
          return;
        }
      }
    }

    document.addEventListener('keydown', handleKeyDown, true);
    return () => document.removeEventListener('keydown', handleKeyDown, true);
  }, [entries]);
}
