/** Supported exchanges. */
export enum Exchange {
  Binance = "binance",
  Coinbase = "coinbase",
  Bybit = "bybit",
  OKX = "okx",
  UniswapV3 = "uniswap-v3",
  Raydium = "raydium",
}

/** Market type classification. */
export enum MarketType {
  Spot = "spot",
  Perpetual = "perpetual",
  Futures = "futures",
  DEX = "dex",
}

/** Symbol metadata from an exchange. */
export interface SymbolInfo {
  /** Exchange-specific symbol string (e.g., "BTCUSDT"). */
  symbol: string;
  /** Human-readable name (e.g., "Bitcoin / Tether"). */
  name: string;
  /** Base asset (e.g., "BTC"). */
  baseAsset: string;
  /** Quote asset (e.g., "USDT"). */
  quoteAsset: string;
  /** Market type. */
  marketType: MarketType;
  /** Source exchange. */
  exchange: Exchange;
  /** Price precision (decimal places). */
  pricePrecision: number;
  /** Quantity precision (decimal places). */
  quantityPrecision: number;
  /** Minimum order size in base currency. */
  minOrderSize: number;
  /** Tick size (minimum price increment). */
  tickSize: number;
  /** On-chain data (for DEX instruments). */
  chain?: string;
  /** Contract address (for DEX instruments). */
  contractAddress?: string;
  /** DEX pool address. */
  poolAddress?: string;
}

/** Connection status for an exchange adapter. */
export enum ConnectionStatus {
  Disconnected = "disconnected",
  Connecting = "connecting",
  Connected = "connected",
  Reconnecting = "reconnecting",
  Error = "error",
}

/** Exchange connection state. */
export interface ExchangeConnection {
  /** Exchange identifier. */
  exchange: Exchange;
  /** Current connection status. */
  status: ConnectionStatus;
  /** Messages received per second. */
  messageRate: number;
  /** Current latency in milliseconds. */
  latencyMs: number;
  /** Number of active subscriptions. */
  subscriptionCount: number;
  /** Last error message (if status is Error). */
  lastError?: string;
  /** Timestamp of last successful message. */
  lastMessageAt: number;
}

/** Subscription handle returned by subscribe methods. */
export interface Subscription {
  /** Unsubscribe and clean up resources. */
  unsubscribe(): void;
  /** Whether the subscription is currently active. */
  readonly active: boolean;
}
