import { useCallback, useMemo } from 'react';
import { getDeskModalAPI } from '../desk/desk-detection';

/** Return type for the useDeskModalStorage hook. */
export interface UseDeskModalStorageResult {
  /** Get a value by key. Returns null if the key does not exist. */
  get: (key: string) => Promise<string | null>;
  /** Set a value by key. Overwrites existing values. */
  set: (key: string, value: string) => Promise<void>;
  /** Remove a value by key. No-op if the key does not exist. */
  remove: (key: string) => Promise<void>;
  /** List all keys for this app. */
  list: () => Promise<string[]>;
}

/** LocalStorage namespace prefix for non-DeskModal environments. */
const LS_PREFIX = 'ts.';

/**
 * Hook providing per-app persistent storage.
 *
 * When running inside DeskModal, delegates to `window.deskmodal.appStorage`
 * which stores data in the native Tauri app-scoped store.
 *
 * When running outside DeskModal, falls back to `localStorage` with a
 * namespace prefix of `ts.<appId>.` to avoid key collisions.
 */
export function useDeskModalStorage(appId: string): UseDeskModalStorageResult {
  const get = useCallback(
    async (key: string): Promise<string | null> => {
      const api = getDeskModalAPI();
      if (api && 'appStorage' in api) {
        const storage = (api as unknown as { appStorage: AppStorageAPI }).appStorage;
        return storage.get(appId, key);
      }
      // localStorage fallback
      const item = localStorage.getItem(`${LS_PREFIX}${appId}.${key}`);
      return item;
    },
    [appId],
  );

  const set = useCallback(
    async (key: string, value: string): Promise<void> => {
      const api = getDeskModalAPI();
      if (api && 'appStorage' in api) {
        const storage = (api as unknown as { appStorage: AppStorageAPI }).appStorage;
        await storage.set(appId, key, value);
        return;
      }
      localStorage.setItem(`${LS_PREFIX}${appId}.${key}`, value);
    },
    [appId],
  );

  const remove = useCallback(
    async (key: string): Promise<void> => {
      const api = getDeskModalAPI();
      if (api && 'appStorage' in api) {
        const storage = (api as unknown as { appStorage: AppStorageAPI }).appStorage;
        await storage.delete(appId, key);
        return;
      }
      localStorage.removeItem(`${LS_PREFIX}${appId}.${key}`);
    },
    [appId],
  );

  const list = useCallback(async (): Promise<string[]> => {
    const api = getDeskModalAPI();
    if (api && 'appStorage' in api) {
      const storage = (api as unknown as { appStorage: AppStorageAPI }).appStorage;
      return storage.list(appId);
    }
    // localStorage fallback: scan for keys with the app prefix
    const prefix = `${LS_PREFIX}${appId}.`;
    const keys: string[] = [];
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.startsWith(prefix)) {
        keys.push(k.slice(prefix.length));
      }
    }
    return keys;
  }, [appId]);

  return useMemo(() => ({ get, set, remove, list }), [get, set, remove, list]);
}

/** Shape of the DeskModal appStorage API. */
interface AppStorageAPI {
  get(appId: string, key: string): Promise<string | null>;
  set(appId: string, key: string, value: string): Promise<void>;
  delete(appId: string, key: string): Promise<void>;
  list(appId: string): Promise<string[]>;
}
