import { useState, useEffect, useRef, useCallback } from 'react';
import { useFdc3, INTENTS } from '@deskmodal/fdc3';
import type { Context, Listener, CryptoInstrumentContext } from '@deskmodal/fdc3';
import { useWatchlistStore } from '../store/watchlist-store';

/**
 * Extends the DesktopAgent type with addIntentListener for type-safe usage.
 */
interface AgentWithIntentListener {
  addIntentListener(
    intent: string,
    handler: (context: Context) => Promise<Context | void>,
  ): Promise<Listener>;
}

/** Data exposed by the ViewQuote intent handler for the UI to consume. */
export interface ViewQuoteIntentResult {
  /** The ticker that should be scrolled to / highlighted, or null. */
  targetTicker: string | null;
  /** Clear the target after the UI has handled it. */
  clearTarget: () => void;
}

/**
 * Register a handler for the ViewQuote intent.
 *
 * When an `fdc3.instrument` context is received:
 * - If the instrument is already in the watchlist, sets it as the scroll target.
 * - If the instrument is not in the watchlist, adds it and sets it as the target.
 *
 * Returns the target ticker for the UI to scroll to / highlight,
 * and a function to clear the target after handling.
 */
export function useViewQuoteIntent(): ViewQuoteIntentResult {
  const fdc3 = useFdc3();
  const addSymbol = useWatchlistStore((s) => s.addSymbol);
  const [targetTicker, setTargetTicker] = useState<string | null>(null);

  const addSymbolRef = useRef(addSymbol);
  addSymbolRef.current = addSymbol;

  useEffect(() => {
    if (!fdc3) return;

    const agent = fdc3 as unknown as AgentWithIntentListener;
    if (typeof agent.addIntentListener !== 'function') return;

    let listener: Listener | undefined;
    let cancelled = false;

    agent
      .addIntentListener(INTENTS.ViewQuote, (context: Context) => {
        if (cancelled) return Promise.resolve();

        if (context.type !== 'fdc3.instrument') return Promise.resolve();

        const instrument = context as unknown as CryptoInstrumentContext;
        const ticker = instrument.id?.ticker;
        if (!ticker) return Promise.resolve();

        // Ensure the symbol exists in the watchlist
        addSymbolRef.current(ticker);

        // Set as target for scroll/highlight
        setTargetTicker(ticker);

        return Promise.resolve();
      })
      .then(
        (l) => {
          if (cancelled) {
            l.unsubscribe();
          } else {
            listener = l;
          }
        },
        () => {
          // Intent listener registration failed -- degrade gracefully
        },
      );

    return () => {
      cancelled = true;
      if (listener) {
        listener.unsubscribe();
      }
    };
  }, [fdc3]);

  const clearTarget = useCallback(() => {
    setTargetTicker(null);
  }, []);

  return { targetTicker, clearTarget };
}
