import { Exchange, MarketType } from '../types/common';

/** Metadata for a supported exchange. */
interface ExchangeMetadata {
  /** Exchange enum value. */
  id: Exchange;
  /** Display name. */
  name: string;
  /** Supported market types on this exchange. */
  marketTypes: MarketType[];
  /** Whether this is a decentralized exchange. */
  isDex: boolean;
}

/** Exchange metadata keyed by Exchange enum value. */
