/**
 * Hook for initiating cross-app drag operations from a source app.
 *
 * Uses the DeskModal drag-drop extension (postMessage bridge to the shell)
 * when available. The shell renders an overlay with drop target highlights
 * and delivers the context to the target app on drop.
 *
 * @example
 * ```tsx
 * const { startDrag, isDragging } = useCrossAppDragSource();
 *
 * <div onMouseDown={(e) => {
 *   const ctx = createInstrumentContext(symbolInfo);
 *   startDrag(ctx, e);
 * }} />
 * ```
 */

import { useCallback, useEffect, useRef, useState } from "react";
import type { Context } from "../fdc3-types";
import { createDragDropContext } from "../contexts/drag-drop-context";
import type { DragOperation } from "../contexts/drag-drop-context";

/** Minimum distance (px) the pointer must move before a drag starts. */
const DRAG_THRESHOLD = 8;

export interface UseCrossAppDragSourceResult {
  /** Begin tracking a potential drag. Call on mousedown. */
  startDrag: (
    context: Context,
    event: React.MouseEvent,
    operation?: DragOperation,
  ) => void;
  /** Whether a drag is currently active. */
  isDragging: boolean;
  /** Cancel the current drag programmatically. */
  cancelDrag: () => void;
}

export function useCrossAppDragSource(): UseCrossAppDragSourceResult {
  const [isDragging, setIsDragging] = useState(false);
  const startPos = useRef<{ x: number; y: number } | null>(null);
  const contextRef = useRef<Context | null>(null);
  const operationRef = useRef<DragOperation>("link");
  const activeRef = useRef(false);
  const cleanupRef = useRef<(() => void) | null>(null);

  const postToShell = useCallback(
    (type: string, payload: Record<string, unknown>) => {
      try {
        window.parent.postMessage({ type, payload }, "*");
      } catch {
        // Silently fail if not in iframe or postMessage blocked
      }
    },
    [],
  );

  const endDrag = useCallback(
    (cancelled: boolean) => {
      if (!activeRef.current) return;
      activeRef.current = false;
      setIsDragging(false);
      startPos.current = null;
      contextRef.current = null;
      cleanupRef.current?.();
      cleanupRef.current = null;
      postToShell("deskmodal:dragEnd", { cancelled });
    },
    [postToShell],
  );

  const cancelDrag = useCallback(() => endDrag(true), [endDrag]);

  const startDrag = useCallback(
    (context: Context, event: React.MouseEvent, operation: DragOperation = "link") => {
      // Store initial position for threshold detection
      startPos.current = { x: event.clientX, y: event.clientY };
      contextRef.current = context;
      operationRef.current = operation;

      const handleMove = (e: MouseEvent) => {
        if (!startPos.current) return;

        const dx = e.clientX - startPos.current.x;
        const dy = e.clientY - startPos.current.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        if (dist < DRAG_THRESHOLD) return;

        if (!activeRef.current && contextRef.current) {
          // Threshold crossed — initiate cross-app drag
          activeRef.current = true;
          setIsDragging(true);

          const dragCtx = createDragDropContext(
            contextRef.current,
            operationRef.current,
          );
          postToShell("deskmodal:dragStart", {
            context: dragCtx,
            cursorX: e.clientX,
            cursorY: e.clientY,
          });
        }

        if (activeRef.current) {
          // Send cursor updates for the shell overlay to track
          postToShell("deskmodal:dragMove", {
            cursorX: e.clientX,
            cursorY: e.clientY,
          });
        }
      };

      const handleUp = () => {
        if (activeRef.current) {
          // Let the shell handle the drop — it knows which iframe the cursor is over
          endDrag(false);
        } else {
          // Threshold never crossed — just clean up
          startPos.current = null;
          contextRef.current = null;
          cleanup();
        }
      };

      const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === "Escape") {
          endDrag(true);
        }
      };

      const cleanup = () => {
        document.removeEventListener("mousemove", handleMove);
        document.removeEventListener("mouseup", handleUp);
        document.removeEventListener("keydown", handleKeyDown);
      };

      cleanupRef.current = cleanup;
      document.addEventListener("mousemove", handleMove);
      document.addEventListener("mouseup", handleUp);
      document.addEventListener("keydown", handleKeyDown);
    },
    [postToShell, endDrag],
  );

  // Clean up document listeners on unmount to prevent leaks
  useEffect(() => {
    return () => {
      cleanupRef.current?.();
      cleanupRef.current = null;
    };
  }, []);

  // Clean up document listeners if component unmounts mid-drag
  useEffect(() => {
    return () => {
      cleanupRef.current?.();
      cleanupRef.current = null;
    };
  }, []);

  return { startDrag, isDragging, cancelDrag };
}
