import { useCallback, type CSSProperties } from 'react';
import { Button } from '../../primitives';
import { Plus } from 'lucide-react';
import { ConditionRow } from './ConditionRow';

/* -------------------------------------------------------------------------- */
/*  ConditionBuilder                                                          */
/*  Composable condition rows with AND/OR logic for multi-condition alerts.   */
/*  Manages adding, removing, and modifying condition rows.                   */
/*  Uses --ts-input-*, --ts-border-* tokens.                                  */
/* -------------------------------------------------------------------------- */

export interface ConditionConfig {
  id: string;
  source: string;
  operator: string;
  value: number | string;
}

export interface ConditionBuilderProps {
  /** Current conditions. */
  conditions: ConditionConfig[];
  /** Called when conditions change (add, remove, modify). */
  onConditionsChange: (conditions: ConditionConfig[]) => void;
  /** Logical operator connecting conditions. */
  logicOperator: 'and' | 'or';
  /** Called when the logic operator changes. */
  onLogicOperatorChange: (op: 'and' | 'or') => void;
  /** Available sources for condition source dropdown. */
  sources: Array<{ value: string; label: string; group: string }>;
  /** Available operators for condition operator dropdown. */
  operators: Array<{ value: string; label: string }>;
  /** Maximum number of conditions. Default 10. */
  maxConditions?: number;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-condition-builder-styles';

function ensureConditionBuilderStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-condition-logic-toggle]:hover {
      background: oklch(0.50 0.005 260 / 0.08);
    }
    [data-ts-condition-logic-toggle]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureConditionBuilderStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 0,
};

const logicToggleStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 24,
  padding: '0 var(--ts-space-2)',
  fontSize: 'var(--ts-font-xs)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  fontFamily: 'inherit',
  color: 'var(--ts-accent-default)',
  borderRadius: 'var(--ts-radius-sm)',
  cursor: 'pointer',
  transition: 'background 100ms',
  alignSelf: 'flex-start',
  marginLeft: 'var(--ts-space-4)',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  boxSizing: 'border-box',
};

const addButtonStyle: CSSProperties = {
  marginTop: 'var(--ts-space-2)',
  alignSelf: 'flex-start',
};

const summaryStyle: CSSProperties = {
  marginTop: 'var(--ts-space-3)',
  padding: 'var(--ts-space-2) var(--ts-space-3)',
  background: 'oklch(0.50 0.005 260 / 0.04)',
  borderRadius: 'var(--ts-radius-sm)',
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
  lineHeight: 1.5,
};

/* ----- Helpers ----------------------------------------------------------- */

function generateId(): string {
  return `cond-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
}

function buildSummary(
  conditions: ConditionConfig[],
  logicOperator: 'and' | 'or',
  sources: Array<{ value: string; label: string }>,
  operators: Array<{ value: string; label: string }>,
): string {
  if (conditions.length === 0) return '';

  const parts = conditions.map((c) => {
    const sourceLabel = sources.find((s) => s.value === c.source)?.label ?? c.source;
    const opLabel = operators.find((o) => o.value === c.operator)?.label ?? c.operator;
    const valueDisplay = typeof c.value === 'number' ? c.value.toLocaleString() : c.value;
    return `${sourceLabel} ${opLabel} ${valueDisplay}`;
  });

  const connector = logicOperator === 'and' ? ' AND ' : ' OR ';
  return `Alert when ${parts.join(connector)}`;
}

/* ----- Component --------------------------------------------------------- */

export function ConditionBuilder({
  conditions,
  onConditionsChange,
  logicOperator,
  onLogicOperatorChange,
  sources,
  operators,
  maxConditions = 10,
}: ConditionBuilderProps): React.JSX.Element {
  const canAddMore = conditions.length < maxConditions;
  const showRemove = conditions.length > 1;

  const handleChange = useCallback(
    (id: string, field: 'source' | 'operator' | 'value', newValue: string | number) => {
      const updated = conditions.map((c) =>
        c.id === id ? { ...c, [field]: newValue } : c,
      );
      onConditionsChange(updated);
    },
    [conditions, onConditionsChange],
  );

  const handleRemove = useCallback(
    (id: string) => {
      if (conditions.length <= 1) return;
      onConditionsChange(conditions.filter((c) => c.id !== id));
    },
    [conditions, onConditionsChange],
  );

  const handleAdd = useCallback(() => {
    if (!canAddMore) return;
    const newCondition: ConditionConfig = {
      id: generateId(),
      source: sources[0]?.value ?? '',
      operator: operators[0]?.value ?? '',
      value: 0,
    };
    onConditionsChange([...conditions, newCondition]);
  }, [canAddMore, conditions, onConditionsChange, sources, operators]);

  const handleToggleLogic = useCallback(() => {
    onLogicOperatorChange(logicOperator === 'and' ? 'or' : 'and');
  }, [logicOperator, onLogicOperatorChange]);

  const summary = buildSummary(conditions, logicOperator, sources, operators);

  return (
    <div data-ts-condition-builder="" style={containerStyle}>
      {conditions.map((condition, i) => (
        <div key={condition.id}>
          <ConditionRow
            id={condition.id}
            index={i + 1}
            source={condition.source}
            operator={condition.operator}
            value={condition.value}
            sources={sources}
            operators={operators}
            onChange={handleChange}
            onRemove={handleRemove}
            showRemove={showRemove}
          />
          {i < conditions.length - 1 ? (
            <button
              type="button"
              data-ts-condition-logic-toggle=""
              style={logicToggleStyle}
              onClick={handleToggleLogic}
              aria-label={`Logic operator: ${logicOperator}. Click to toggle.`}
            >
              {logicOperator.toUpperCase()}
            </button>
          ) : null}
        </div>
      ))}
      {canAddMore ? (
        <div style={addButtonStyle}>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleAdd}
            data-testid="add-condition"
          >
            <Plus size={14} style={{ marginRight: 'var(--ts-space-1)' }} />
            Add condition
          </Button>
        </div>
      ) : null}
      {summary ? (
        <div style={summaryStyle} data-testid="condition-summary" aria-live="polite">
          {summary}
        </div>
      ) : null}
    </div>
  );
}

ConditionBuilder.displayName = 'ConditionBuilder';
