import { useCallback, useMemo, type CSSProperties } from 'react';
import { PriceDisplay, PriceChange } from '../../financial';

/* -------------------------------------------------------------------------- */
/*  MiniChartCard                                                             */
/*  Compact chart card for screener grid view with sparkline and price.       */
/*  Composes PriceDisplay + PriceChange. Uses --ts-screener-mini-chart-*      */
/* -------------------------------------------------------------------------- */

export interface MiniChartCardProps {
  /** Ticker symbol (e.g., "BTC"). */
  ticker: string;
  /** Full instrument name (e.g., "Bitcoin"). */
  name: string;
  /** Icon URL or placeholder. */
  iconUrl?: string;
  /** Current price. */
  price: number;
  /** Previous price for direction. */
  previousPrice?: number;
  /** Price change absolute value. */
  change: number;
  /** Price change percentage. */
  changePercent: number;
  /** Sparkline data points (24h). */
  sparklineData: number[];
  /** Price decimal precision. */
  precision?: number;
  /** Called when the card is clicked. */
  onClick?: () => void;
  /** Whether this card is selected. */
  selected?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-mini-chart-card-styles';

function ensureMiniChartCardStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-mini-chart-card]:hover {
      background: var(--ts-screener-mini-chart-card-bg-hover, var(--ts-panel-header-bg));
      border-color: var(--ts-accent-default);
    }
    [data-ts-mini-chart-card]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-mini-chart-card][data-selected] {
      border-color: var(--ts-accent-default);
      background: var(--ts-accent-subtle);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureMiniChartCardStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const cardStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-screener-mini-chart-card-gap, var(--ts-space-2))',
  width: 'var(--ts-screener-mini-chart-card-width, 220px)',
  padding: 'var(--ts-screener-mini-chart-card-padding, var(--ts-space-3))',
  background: 'var(--ts-screener-mini-chart-card-bg, var(--ts-panel-bg))',
  border: '1px solid var(--ts-screener-mini-chart-card-border, var(--ts-panel-border))',
  borderRadius: 'var(--ts-screener-mini-chart-card-radius, var(--ts-radius-sm))',
  cursor: 'pointer',
  transition: 'background 150ms, border-color 150ms',
  boxSizing: 'border-box',
  outline: 'none',
};

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const iconStyle: CSSProperties = {
  width: 24,
  height: 24,
  borderRadius: '50%',
  background: 'var(--ts-text-tertiary)',
  flexShrink: 0,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  fontSize: '10px',
  fontWeight: 'var(--ts-font-weight-bold)' as unknown as number,
  color: 'var(--ts-text-primary)',
  overflow: 'hidden',
};

const tickerStyle: CSSProperties = {
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-primary)',
  fontSize: 'var(--ts-font-md)',
};

const nameStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-xs)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
  flex: 1,
};

const sparklineContainerStyle: CSSProperties = {
  width: '100%',
  height: 40,
  flexShrink: 0,
};

const footerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
};

/* ----- Inline Sparkline -------------------------------------------------- */

function CardSparkline({ data }: { data: number[] }): React.JSX.Element {
  const { points, fillPoints, isPositive } = useMemo(() => {
    if (data.length < 2) return { points: '', fillPoints: '', isPositive: true };

    const w = 190;
    const h = 40;
    const pad = 1;
    const minVal = Math.min(...data);
    const maxVal = Math.max(...data);
    const range = maxVal - minVal || 1;
    const stepX = (w - pad * 2) / (data.length - 1);

    const pts = data.map((v, i) => {
      const x = pad + i * stepX;
      const y = h - pad - ((v - minVal) / range) * (h - pad * 2);
      return `${x},${y}`;
    });

    const linePoints = pts.join(' ');
    const fillPts = `${pad},${h} ${linePoints} ${pad + (data.length - 1) * stepX},${h}`;

    return {
      points: linePoints,
      fillPoints: fillPts,
      isPositive: (data[data.length - 1] ?? 0) >= (data[0] ?? 0),
    };
  }, [data]);

  const strokeColor = isPositive
    ? 'var(--ts-price-up-text, #22c55e)'
    : 'var(--ts-price-down-text, #ef4444)';
  const fillColor = isPositive
    ? 'var(--ts-price-change-up-bg, rgba(34, 197, 94, 0.1))'
    : 'var(--ts-price-change-down-bg, rgba(239, 68, 68, 0.1))';

  return (
    <svg
      width="100%"
      height={40}
      viewBox="0 0 190 40"
      preserveAspectRatio="none"
      style={{ display: 'block' }}
      aria-hidden
    >
      <polygon points={fillPoints} fill={fillColor} />
      <polyline
        points={points}
        fill="none"
        stroke={strokeColor}
        strokeWidth={1.5}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

/* ----- Component --------------------------------------------------------- */

export function MiniChartCard({
  ticker,
  name,
  iconUrl,
  price,
  previousPrice,
  change,
  changePercent,
  sparklineData,
  precision = 2,
  onClick,
  selected = false,
}: MiniChartCardProps): React.JSX.Element {
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (onClick !== undefined && (e.key === 'Enter' || e.key === ' ')) {
        e.preventDefault();
        onClick();
      }
    },
    [onClick],
  );

  return (
    <div
      data-ts-mini-chart-card=""
      {...(selected ? { 'data-selected': '' } : {})}
      style={cardStyle}
      onClick={onClick}
      onKeyDown={handleKeyDown}
      tabIndex={onClick !== undefined ? 0 : undefined}
      role={onClick !== undefined ? 'button' : undefined}
      aria-label={`${ticker} ${name}: $${price.toFixed(precision)}, ${changePercent >= 0 ? '+' : ''}${changePercent.toFixed(2)}%`}
    >
      <div style={headerStyle}>
        <div style={iconStyle}>
          {iconUrl !== undefined ? (
            <img
              src={iconUrl}
              alt={ticker}
              style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }}
            />
          ) : (
            ticker.slice(0, 2).toUpperCase()
          )}
        </div>
        <span style={tickerStyle}>{ticker}</span>
        <span style={nameStyle}>{name}</span>
      </div>

      <div style={sparklineContainerStyle}>
        {sparklineData.length >= 2 && <CardSparkline data={sparklineData} />}
      </div>

      <div style={footerStyle}>
        <PriceDisplay
          value={price}
          previousValue={previousPrice}
          precision={precision}
          size="sm"
          showFlash={false}
        />
        <PriceChange
          value={change}
          percentage={changePercent}
          showAbsolute={false}
          showPercentage={true}
          size="sm"
        />
      </div>
    </div>
  );
}

MiniChartCard.displayName = 'MiniChartCard';
