import { useRef, useEffect, useCallback } from 'react';

/** Configuration for a debounced ARIA live region. */
export interface LiveRegionConfig {
  /** 'polite' for non-urgent updates, 'assertive' for urgent alerts. */
  readonly politeness: 'polite' | 'assertive';
  /** Debounce interval in ms. Prevents screen reader flooding. Default: 1000. */
  readonly debounceMs?: number;
  /** Role attribute. Default: 'status' for polite, 'alert' for assertive. */
  readonly role?: string;
}

/** Visually-hidden style that keeps the element in the accessibility tree. */
const VISUALLY_HIDDEN: React.CSSProperties = {
  position: 'absolute',
  width: 1,
  height: 1,
  padding: 0,
  margin: -1,
  overflow: 'hidden',
  clip: 'rect(0, 0, 0, 0)',
  whiteSpace: 'nowrap',
  border: 0,
};

/**
 * Hook that manages an ARIA live region element for announcing real-time updates.
 * Returns a ref to attach to the live region container and an announce function.
 *
 * Debounces rapid updates to prevent screen reader flooding.
 * The debounce keeps only the latest message within each interval.
 */
export function useLiveRegion(config: LiveRegionConfig): {
  ref: React.RefObject<HTMLDivElement | null>;
  announce: (message: string) => void;
} {
  const ref = useRef<HTMLDivElement | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const debounceMs = config.debounceMs ?? 1000;

  useEffect(() => {
    return () => {
      if (timerRef.current !== null) {
        clearTimeout(timerRef.current);
        timerRef.current = null;
      }
    };
  }, []);

  const announce = useCallback(
    (message: string) => {
      if (timerRef.current !== null) {
        clearTimeout(timerRef.current);
      }

      timerRef.current = setTimeout(() => {
        timerRef.current = null;
        if (ref.current !== null) {
          ref.current.textContent = message;
        }
      }, debounceMs);
    },
    [debounceMs],
  );

  return { ref, announce };
}

/** Props for the LiveRegion component. */
export interface LiveRegionProps {
  /** The message to announce. Changes trigger screen reader announcements. */
  readonly message: string;
  /** 'polite' queues behind current speech; 'assertive' interrupts. Default: 'polite'. */
  readonly politeness?: 'polite' | 'assertive';
  /** Explicit ARIA role. Default: 'status' for polite, 'alert' for assertive. */
  readonly role?: string;
}

/**
 * Invisible ARIA live region component.
 * Renders a visually-hidden div with the appropriate aria-live attribute.
 * Screen readers detect changes to `message` and announce them.
 */
export function LiveRegion({
  message,
  politeness = 'polite',
  role,
}: LiveRegionProps): React.JSX.Element {
  const resolvedRole = role ?? (politeness === 'assertive' ? 'alert' : 'status');

  return (
    <div aria-live={politeness} role={resolvedRole} style={VISUALLY_HIDDEN}>
      {message}
    </div>
  );
}

LiveRegion.displayName = 'LiveRegion';
