import { forwardRef, useCallback, type CSSProperties } from 'react';
import { BarChart3 } from 'lucide-react';
import { Panel, Toolbar, Select, EmptyState } from '../../primitives';
import { PriceChange, formatCompactNumber } from '../../financial';

/* -------------------------------------------------------------------------- */
/*  OpenInterestDisplay                                                       */
/*  Shows aggregate open interest with exchange breakdown and chart controls. */
/*  Uses --ts-metric-card-* and --ts-viz-shell-* tokens.                      */
/* -------------------------------------------------------------------------- */

export type OITimePeriod = '1h' | '4h' | '12h' | '24h' | '7d';
export type OIChartType = 'stacked-area' | 'line' | 'delta-bar';

export interface OpenInterestDisplayProps {
  /** Panel title. */
  title?: string;
  /** Aggregate OI value. */
  aggregateValue: number;
  /** Change percentage. */
  changePercent: number;
  /** Available exchanges for the legend/filter. */
  exchanges: Array<{ name: string; color: string; enabled: boolean }>;
  /** Called when exchange visibility toggles. */
  onExchangeToggle?: (exchangeName: string) => void;
  /** Currently selected time period. */
  timePeriod: OITimePeriod;
  /** Called when time period changes. */
  onTimePeriodChange: (period: OITimePeriod) => void;
  /** Currently selected chart type. */
  chartType: OIChartType;
  /** Called when chart type changes. */
  onChartTypeChange: (type: OIChartType) => void;
  /** Called when the user clicks to view full chart. */
  onViewChart?: () => void;
}

/* ----- Style injection --------------------------------------------------- */

const OI_DISPLAY_STYLE_ID = 'ts-open-interest-display-styles';

function ensureOpenInterestDisplayStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(OI_DISPLAY_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = OI_DISPLAY_STYLE_ID;
  sheet.textContent = `
    [data-ts-open-interest-display] [data-ts-exchange-toggle]:hover {
      opacity: 0.8;
    }
    [data-ts-open-interest-display] [data-ts-exchange-toggle]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureOpenInterestDisplayStyles();
}

/* ----- Constants --------------------------------------------------------- */

const TIME_PERIOD_OPTIONS: Array<{ value: OITimePeriod; label: string }> = [
  { value: '1h', label: '1H' },
  { value: '4h', label: '4H' },
  { value: '12h', label: '12H' },
  { value: '24h', label: '24H' },
  { value: '7d', label: '7D' },
];

const CHART_TYPE_OPTIONS: Array<{ value: string; label: string }> = [
  { value: 'stacked-area', label: 'Stacked Area' },
  { value: 'line', label: 'Line' },
  { value: 'delta-bar', label: 'Delta Bar' },
];

/* ----- Styles ------------------------------------------------------------ */

const headerValueStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-3)',
  padding: 'var(--ts-space-3)',
};

const aggregateValueStyle: CSSProperties = {
  fontFamily: 'var(--ts-metric-card-value-font)',
  fontSize: 'var(--ts-font-xl)',
  fontWeight: 'var(--ts-font-weight-bold)' as unknown as number,
  color: 'var(--ts-text-primary)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
  fontFeatureSettings: "'tnum' 1, 'zero' 1",
};

const vizContainerStyle: CSSProperties = {
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  background: 'var(--ts-viz-shell-bg)',
  minHeight: 200,
};

const exchangeLegendStyle: CSSProperties = {
  display: 'flex',
  flexWrap: 'wrap',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-2) var(--ts-space-3)',
};

const exchangeToggleStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  cursor: 'pointer',
  padding: '2px var(--ts-space-1)',
  borderRadius: 'var(--ts-radius-sm)',
  transition: 'opacity 150ms',
};

const exchangeDotStyle = (color: string, enabled: boolean): CSSProperties => ({
  width: 8,
  height: 8,
  borderRadius: '50%',
  background: color,
  opacity: enabled ? 1 : 0.3,
  flexShrink: 0,
});

export const OpenInterestDisplay = forwardRef<HTMLDivElement, OpenInterestDisplayProps>(
  function OpenInterestDisplay(
    {
      title = 'Open Interest',
      aggregateValue,
      changePercent,
      exchanges,
      onExchangeToggle,
      timePeriod,
      onTimePeriodChange,
      chartType,
      onChartTypeChange,
      onViewChart,
    },
    ref,
  ) {
    const handleExchangeToggle = useCallback(
      (name: string) => {
        onExchangeToggle?.(name);
      },
      [onExchangeToggle],
    );

    return (
      <div ref={ref} data-ts-open-interest-display="">
        <Panel
          title={title}
          actions={
            onViewChart !== undefined ? (
              <button
                type="button"
                onClick={onViewChart}
                style={{
                  all: 'unset',
                  cursor: 'pointer',
                  fontSize: 'var(--ts-font-sm)',
                  color: 'var(--ts-accent-default)',
                }}
                aria-label="View full chart"
              >
                View Chart
              </button>
            ) : undefined
          }
        >
          {/* Aggregate value display */}
          <div style={headerValueStyle}>
            <span style={aggregateValueStyle}>
              ${formatCompactNumber(aggregateValue)}
            </span>
            <PriceChange
              value={changePercent > 0 ? 1 : changePercent < 0 ? -1 : 0}
              percentage={changePercent}
              showAbsolute={false}
              showPercentage
              size="sm"
            />
          </div>

          {/* Controls */}
          <Toolbar>
            <Toolbar.Group>
              {TIME_PERIOD_OPTIONS.map((opt) => (
                <Toolbar.Item
                  key={opt.value}
                  active={timePeriod === opt.value}
                  onClick={() => onTimePeriodChange(opt.value)}
                  aria-label={`Time period ${opt.label}`}
                >
                  {opt.label}
                </Toolbar.Item>
              ))}
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <Select
                options={CHART_TYPE_OPTIONS}
                value={chartType}
                onValueChange={(v) => onChartTypeChange(v as OIChartType)}
                size="sm"
                label="Chart type"
              />
            </Toolbar.Group>
          </Toolbar>

          {/* Chart area placeholder */}
          <div style={vizContainerStyle}>
            <EmptyState
              icon={<BarChart3 size={40} />}
              title="Connect to data source"
              description="Open interest chart will render here when connected to market data."
            />
          </div>

          {/* Exchange legend */}
          <div style={exchangeLegendStyle}>
            {exchanges.map((ex) => (
              <button
                key={ex.name}
                type="button"
                data-ts-exchange-toggle=""
                style={{
                  ...exchangeToggleStyle,
                  opacity: ex.enabled ? 1 : 0.5,
                }}
                onClick={() => handleExchangeToggle(ex.name)}
                aria-label={`Toggle ${ex.name}`}
                aria-pressed={ex.enabled}
              >
                <span style={exchangeDotStyle(ex.color, ex.enabled)} />
                {ex.name}
              </button>
            ))}
          </div>
        </Panel>
      </div>
    );
  },
);

OpenInterestDisplay.displayName = 'OpenInterestDisplay';
