import { useState, useCallback, useRef, type CSSProperties, type KeyboardEvent } from 'react';
import { Popover } from '../primitives';
import { Input } from '../primitives';
import { Slider } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  ColorPicker                                                               */
/*  Popover-based color picker with preset swatches, hex input, opacity.      */
/*  Uses --ts-color-picker-* and --ts-overlay-* tokens.                       */
/* -------------------------------------------------------------------------- */

export interface ColorPickerProps {
  /** Current color value (hex string, e.g. "#ff0000"). */
  value: string;
  /** Called when a new color is selected. */
  onValueChange: (color: string) => void;
  /** Preset color swatches displayed in the grid. */
  presets?: string[];
  /** Recently used colors displayed in a separate row. */
  recentColors?: string[];
  /** Whether to show the opacity slider. */
  showOpacity?: boolean;
  /** Current opacity value (0–1). */
  opacity?: number;
  /** Called when opacity changes. */
  onOpacityChange?: (opacity: number) => void;
  /** Whether the picker is disabled. */
  disabled?: boolean;
  /** Preferred side for the popover. */
  side?: 'top' | 'right' | 'bottom' | 'left';
  /** Alignment of the popover. */
  align?: 'start' | 'center' | 'end';
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-color-picker-styles';

function ensureColorPickerStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-color-picker-trigger]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-color-picker-trigger]:not(:disabled):hover {
      border-color: var(--ts-color-picker-swatch-selected-border);
    }
    [data-ts-color-picker-trigger]:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
    [data-ts-color-picker-swatch]:hover {
      transform: scale(1.15);
    }
    [data-ts-color-picker-swatch]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
    [data-ts-color-picker-swatch][data-selected] {
      border-color: var(--ts-color-picker-swatch-selected-border);
      box-shadow: 0 0 0 1px var(--ts-color-picker-swatch-selected-border);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureColorPickerStyles();
}

/* ----- Default presets --------------------------------------------------- */

const DEFAULT_PRESETS: string[] = [
  'var(--ts-chart-bull)',
  'var(--ts-chart-bear)',
  'var(--ts-accent-default)',
  'var(--ts-text-primary)',
  'var(--ts-text-secondary)',
  '#ef4444',
  '#f97316',
  '#f59e0b',
  '#eab308',
  '#84cc16',
  '#22c55e',
  '#10b981',
  '#14b8a6',
  '#06b6d4',
  '#0ea5e9',
  '#3b82f6',
  '#6366f1',
  '#8b5cf6',
  '#a855f7',
  '#ec4899',
];

/* ----- Hex validation ---------------------------------------------------- */

const HEX_REGEX = /^#[0-9a-fA-F]{6}$/;

function isValidHex(value: string): boolean {
  return HEX_REGEX.test(value);
}

function normalizeHexInput(raw: string): string {
  let v = raw.trim();
  if (!v.startsWith('#')) {
    v = '#' + v;
  }
  return v;
}

/* ----- Styles ------------------------------------------------------------ */

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-color-picker-swatch-size)',
  height: 'var(--ts-color-picker-swatch-size)',
  borderRadius: 'var(--ts-color-picker-swatch-radius)',
  border: '2px solid var(--ts-color-picker-swatch-border)',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'border-color 150ms, transform 150ms',
  flexShrink: 0,
};

const contentStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '12px',
  padding: '12px',
  minWidth: 200,
};

const sectionLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  margin: 0,
  lineHeight: 1,
};

const gridStyle: CSSProperties = {
  display: 'grid',
  gridTemplateColumns: 'repeat(5, 1fr)',
  gap: '6px',
};

const swatchStyle: CSSProperties = {
  all: 'unset',
  width: 'var(--ts-color-picker-swatch-size)',
  height: 'var(--ts-color-picker-swatch-size)',
  borderRadius: 'var(--ts-color-picker-swatch-radius)',
  border: '1px solid var(--ts-color-picker-swatch-border)',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'transform 150ms',
  flexShrink: 0,
};

const recentRowStyle: CSSProperties = {
  display: 'flex',
  gap: '6px',
  flexWrap: 'wrap',
};

const hexRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
};

const opacityRowStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '4px',
};

const opacityLabelRowStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
};

/* ----- Component --------------------------------------------------------- */

export function ColorPicker({
  value,
  onValueChange,
  presets = DEFAULT_PRESETS,
  recentColors,
  showOpacity = false,
  opacity = 1,
  onOpacityChange,
  disabled = false,
  side = 'bottom',
  align = 'start',
}: ColorPickerProps): React.JSX.Element {
  const [hexInput, setHexInput] = useState(value);
  const [open, setOpen] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleOpenChange = useCallback((nextOpen: boolean) => {
    setOpen(nextOpen);
    if (nextOpen) {
      setHexInput(value);
    }
  }, [value]);

  const handlePresetClick = useCallback((color: string) => {
    onValueChange(color);
    setHexInput(color);
  }, [onValueChange]);

  const handleHexInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value;
    setHexInput(raw);
    const normalized = normalizeHexInput(raw);
    if (isValidHex(normalized)) {
      onValueChange(normalized);
    }
  }, [onValueChange]);

  const handleHexKeyDown = useCallback((e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      const normalized = normalizeHexInput(hexInput);
      if (isValidHex(normalized)) {
        onValueChange(normalized);
        setHexInput(normalized);
      }
    }
  }, [hexInput, onValueChange]);

  const handleOpacityChange = useCallback((vals: number[]) => {
    const v = vals[0];
    if (v !== undefined) {
      onOpacityChange?.(v / 100);
    }
  }, [onOpacityChange]);

  return (
    <Popover open={open} onOpenChange={handleOpenChange}>
      <Popover.Trigger>
        <button
          type="button"
          data-ts-color-picker=""
          data-ts-color-picker-trigger=""
          disabled={disabled}
          aria-label="Pick color"
          style={{
            ...triggerStyle,
            background: value,
          }}
        />
      </Popover.Trigger>
      <Popover.Content side={side} align={align}>
        <div style={contentStyle} data-ts-color-picker-panel="">
          {/* Preset grid */}
          <div>
            <div data-ts-color-picker-grid="" style={gridStyle}>
              {presets.map((color, i) => (
                <button
                  key={`${color}-${i}`}
                  type="button"
                  data-ts-color-picker-swatch=""
                  {...(value === color ? { 'data-selected': '' } : {})}
                  style={{ ...swatchStyle, background: color }}
                  aria-label={`Select color ${color}`}
                  onClick={() => handlePresetClick(color)}
                />
              ))}
            </div>
          </div>

          {/* Recent colors */}
          {recentColors !== undefined && recentColors.length > 0 && (
            <div>
              <p style={sectionLabelStyle}>Recent</p>
              <div style={{ ...recentRowStyle, marginTop: 4 }}>
                {recentColors.map((color, i) => (
                  <button
                    key={`recent-${color}-${i}`}
                    type="button"
                    data-ts-color-picker-swatch=""
                    {...(value === color ? { 'data-selected': '' } : {})}
                    style={{ ...swatchStyle, background: color }}
                    aria-label={`Select recent color ${color}`}
                    onClick={() => handlePresetClick(color)}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Hex input */}
          <div style={hexRowStyle} data-ts-color-picker-input="">
            <div
              style={{
                width: 20,
                height: 20,
                borderRadius: 'var(--ts-color-picker-swatch-radius)',
                background: value,
                border: '1px solid var(--ts-color-picker-swatch-border)',
                flexShrink: 0,
              }}
              aria-hidden="true"
            />
            <Input
              ref={inputRef}
              size="sm"
              value={hexInput}
              onChange={handleHexInputChange}
              onKeyDown={handleHexKeyDown}
              placeholder="#000000"
              aria-label="Hex color"
              style={{ flex: 1, background: 'var(--ts-color-picker-input-bg)' }}
            />
          </div>

          {/* Opacity slider */}
          {showOpacity && (
            <div style={opacityRowStyle}>
              <div style={opacityLabelRowStyle}>
                <span style={sectionLabelStyle}>Opacity</span>
                <span style={sectionLabelStyle}>{Math.round(opacity * 100)}%</span>
              </div>
              <Slider
                value={[Math.round(opacity * 100)]}
                onValueChange={handleOpacityChange}
                min={0}
                max={100}
                step={1}
                label="Opacity"
              />
            </div>
          )}
        </div>
      </Popover.Content>
    </Popover>
  );
}

ColorPicker.displayName = 'ColorPicker';
