import { useCallback } from 'react';
import {
  useFdc3,
  createInstrumentContext,
  MarketType,
  Exchange,
} from '@deskmodal/fdc3';
import type { SymbolInfo } from '@deskmodal/fdc3';

/**
 * Parse a watchlist symbol ID (format "EXCHANGE:SYMBOL") into the exchange
 * and ticker parts. Returns null if the format is unrecognized.
 */
function parseSymbolId(symbolId: string): { exchange: string; ticker: string } | null {
  const colonIdx = symbolId.indexOf(':');
  if (colonIdx === -1) {
    return null;
  }
  return {
    exchange: symbolId.slice(0, colonIdx),
    ticker: symbolId.slice(colonIdx + 1),
  };
}

/**
 * Map a display exchange name (e.g., "BINANCE") to the Exchange enum value.
 * Falls back to Binance for unrecognized exchanges.
 */
function resolveExchange(exchangeUpper: string): Exchange {
  const mapping: Record<string, Exchange> = {
    BINANCE: Exchange.Binance,
    COINBASE: Exchange.Coinbase,
    BYBIT: Exchange.Bybit,
    OKX: Exchange.OKX,
  };
  return mapping[exchangeUpper] ?? Exchange.Binance;
}

/**
 * Derive base and quote assets from a ticker string.
 * Handles common quote suffixes: USDT, USDC, USD, BUSD, BTC, ETH.
 */
function deriveAssets(ticker: string): { baseAsset: string; quoteAsset: string } {
  const quoteSuffixes = ['USDT', 'USDC', 'BUSD', 'USD', 'BTC', 'ETH'];
  for (const suffix of quoteSuffixes) {
    if (ticker.endsWith(suffix) && ticker.length > suffix.length) {
      return {
        baseAsset: ticker.slice(0, -suffix.length),
        quoteAsset: suffix,
      };
    }
  }
  return { baseAsset: ticker, quoteAsset: 'USD' };
}

/**
 * Hook that provides a function to broadcast an FDC3 instrument context
 * on the user channel when a symbol is selected.
 *
 * Gracefully degrades when FDC3 is unavailable — the returned function
 * becomes a no-op, letting the caller safely invoke it in all environments.
 */
export function useFdc3Broadcast(): (symbolId: string) => void {
  const fdc3 = useFdc3();

  const broadcast = useCallback(
    (symbolId: string) => {
      if (!fdc3) {
        return;
      }

      const parsed = parseSymbolId(symbolId);
      if (!parsed) {
        return;
      }

      const exchange = resolveExchange(parsed.exchange);
      const { baseAsset, quoteAsset } = deriveAssets(parsed.ticker);

      const symbolInfo: SymbolInfo = {
        symbol: parsed.ticker,
        name: `${baseAsset} / ${quoteAsset}`,
        baseAsset,
        quoteAsset,
        marketType: MarketType.Spot,
        exchange,
        pricePrecision: 2,
        quantityPrecision: 4,
        minOrderSize: 0,
        tickSize: 0.01,
      };

      const ctx = createInstrumentContext(symbolInfo);
      fdc3.broadcast(ctx).catch(() => {
        // Broadcast failure is non-critical — the local UI already reflects the selection
      });
    },
    [fdc3],
  );

  return broadcast;
}
