import { useCallback, useEffect, useRef } from 'react';
import { useSubscriptionStore, type Subscription } from '../store/subscription-store';
import { useWatchlistStore } from '../store/watchlist-store';

/**
 * Resolve the FDC3 PriceFeedClient subscribe/unsubscribe intents.
 * This mirrors the feeds app's price-feed-client but avoids importing
 * cross-app code — instead it raises FDC3 intents directly.
 */
async function raiseSubscribeIntent(
  exchangeId: string,
  symbol: string,
): Promise<boolean> {
  const fdc3 = window.fdc3;
  if (!fdc3) return false;
  try {
    await fdc3.raiseIntent('deskmodal.SubscribePrices', {
      type: 'deskmodal.command',
      id: { action: 'subscribe' },
      exchangeId,
      symbol,
    } as never);
    return true;
  } catch {
    return false;
  }
}

async function raiseUnsubscribeIntent(
  exchangeId: string,
  symbol: string,
): Promise<boolean> {
  const fdc3 = window.fdc3;
  if (!fdc3) return false;
  try {
    await fdc3.raiseIntent('deskmodal.UnsubscribePrices', {
      type: 'deskmodal.command',
      id: { action: 'unsubscribe' },
      exchangeId,
      symbol,
    } as never);
    return true;
  } catch {
    return false;
  }
}

/**
 * Manages exchange-symbol subscriptions and keeps the watchlist store
 * in sync. Handles FDC3 subscribe/unsubscribe intents and auto-restores
 * subscriptions on mount.
 */
export function useSubscriptionManager(): {
  subscribe: (exchangeId: string, symbol: string) => Promise<boolean>;
  unsubscribe: (exchangeId: string, symbol: string) => Promise<boolean>;
  subscriptions: Subscription[];
  getByExchange: (exchangeId: string) => Subscription[];
} {
  const {
    subscriptions,
    addSubscription,
    removeSubscription,
    getByExchange,
  } = useSubscriptionStore();
  const addSymbol = useWatchlistStore((s) => s.addSymbol);
  const removeSymbolFromStore = useWatchlistStore((s) => s.removeSymbol);
  const restoredRef = useRef(false);

  /** Restore persisted subscriptions on first mount. */
  useEffect(() => {
    if (restoredRef.current) return;
    restoredRef.current = true;
    for (const sub of subscriptions) {
      raiseSubscribeIntent(sub.exchangeId, sub.symbol).catch(() => {});
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const subscribe = useCallback(
    async (exchangeId: string, symbol: string): Promise<boolean> => {
      const ok = await raiseSubscribeIntent(exchangeId, symbol);
      if (ok) {
        addSubscription(exchangeId, symbol);
        // Add the normalized ticker to the watchlist display
        const ticker = symbol.replace('/', '');
        addSymbol(ticker);
      }
      return ok;
    },
    [addSubscription, addSymbol],
  );

  const unsubscribe = useCallback(
    async (exchangeId: string, symbol: string): Promise<boolean> => {
      const ok = await raiseUnsubscribeIntent(exchangeId, symbol);
      if (ok) {
        removeSubscription(exchangeId, symbol);
        // Check if this symbol is still subscribed on another exchange
        const remaining = useSubscriptionStore
          .getState()
          .subscriptions.filter(
            (s) => s.symbol.replace('/', '') === symbol.replace('/', ''),
          );
        if (remaining.length === 0) {
          removeSymbolFromStore(symbol.replace('/', ''));
        }
      }
      return ok;
    },
    [removeSubscription, removeSymbolFromStore],
  );

  return { subscribe, unsubscribe, subscriptions, getByExchange };
}
