import type { TranslationMap } from "./i18n";

/**
 * Flatten a nested record structure into dot-separated keys.
 * { a: { b: "val" } } becomes { "a.b": "val" }
 */
function flatten(
  obj: Record<string, string | Record<string, unknown>>,
  prefix: string = "",
): TranslationMap {
  const result: Record<string, string> = {};

  const keys = Object.keys(obj);
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i]!;
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];
    if (typeof value === "string") {
      result[fullKey] = value;
    } else if (typeof value === "object" && value !== null) {
      Object.assign(result, flatten(value as Record<string, string | Record<string, unknown>>, fullKey));
    }
  }

  return result as TranslationMap;
}

