/**
 * Core types referenced by the FDC3 package.
 *
 * These mirror the types from @deskmodal/core to allow the FDC3 package
 * to compile independently before the full monorepo is wired. When the
 * monorepo is fully operational, these can be replaced with re-exports
 * from @deskmodal/core.
 */

/** Market type classification. */
export enum MarketType {
  Spot = "spot",
  Perpetual = "perpetual",
  Futures = "futures",
  DEX = "dex",
}

/** Supported exchanges. */
export enum Exchange {
  Binance = "binance",
  Coinbase = "coinbase",
  Bybit = "bybit",
  OKX = "okx",
  UniswapV3 = "uniswap-v3",
  Raydium = "raydium",
}

/** Symbol metadata from an exchange. */
export interface SymbolInfo {
  /** Exchange-specific symbol string (e.g., "BTCUSDT"). */
  symbol: string;
  /** Human-readable name (e.g., "Bitcoin / Tether"). */
  name: string;
  /** Base asset (e.g., "BTC"). */
  baseAsset: string;
  /** Quote asset (e.g., "USDT"). */
  quoteAsset: string;
  /** Market type. */
  marketType: MarketType;
  /** Source exchange. */
  exchange: Exchange;
  /** Price precision (decimal places). */
  pricePrecision: number;
  /** Quantity precision (decimal places). */
  quantityPrecision: number;
  /** Minimum order size in base currency. */
  minOrderSize: number;
  /** Tick size (minimum price increment). */
  tickSize: number;
  /** On-chain data (for DEX instruments). */
  chain?: string;
  /** Contract address (for DEX instruments). */
  contractAddress?: string;
  /** DEX pool address. */
  poolAddress?: string;
}
