import { useEffect, useRef } from 'react';
import { useLiveRegion } from '@deskmodal/core';
import { useMarketData } from '@deskmodal/data-layer';
import { useWatchlistStore } from '../store/watchlist-store';

/**
 * Announces price updates to screen readers via an ARIA live region.
 *
 * Reads quotes from the shared `useMarketData()` hook and, when a price
 * changes for a watchlisted symbol, announces the latest value through
 * a polite live region with a 1-second debounce to prevent screen reader
 * flooding during rapid tick streams.
 *
 * Returns a ref to attach to a visually-hidden container element.
 */
export function usePriceAnnouncer(): React.RefObject<HTMLDivElement | null> {
  const { ref, announce } = useLiveRegion({
    politeness: 'polite',
    debounceMs: 1000,
  });

  const prevPricesRef = useRef<Map<string, number>>(new Map());
  const marketData = useMarketData();
  const { symbols } = useWatchlistStore();

  useEffect(() => {
    const prev = prevPricesRef.current;
    const updates: string[] = [];

    for (const symbol of symbols) {
      const tick = marketData.getQuote(symbol);
      if (!tick) continue;

      const prevPrice = prev.get(symbol);
      if (prevPrice !== undefined && prevPrice !== tick.last) {
        updates.push(`${symbol} ${tick.last.toLocaleString()}`);
      }
      prev.set(symbol, tick.last);
    }

    if (updates.length > 0) {
      // Announce the most recent batch of changes.
      // If many symbols update simultaneously, summarize with count.
      if (updates.length <= 3) {
        announce(updates.join(', '));
      } else {
        announce(
          `${updates[0]}, ${updates[1]}, and ${updates.length - 2} more updated`,
        );
      }
    }
  }, [announce, symbols, marketData.version]);

  return ref;
}
