import {
  useCallback,
  type CSSProperties,
} from 'react';
import { IconButton, Slider, Select } from '../primitives';
import {
  History,
  Play,
  Pause,
  SkipForward,
  SkipBack,
} from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ReplayControls                                                            */
/*  Toolbar controls for chart replay/bar replay mode with play/pause,        */
/*  step, speed, and optional seek slider.                                    */
/*  Uses --ts-toolbar-*, --ts-selector-* tokens.                              */
/* -------------------------------------------------------------------------- */

export type ReplaySpeed = 0.5 | 1 | 2 | 5 | 10;

export interface ReplayControlsProps {
  /** Whether replay mode is currently active. */
  active: boolean;
  /** Whether playback is running. */
  playing: boolean;
  /** Called when play/pause is toggled. */
  onPlayPause: () => void;
  /** Called when step forward is clicked. */
  onStepForward: () => void;
  /** Called when step backward is clicked. */
  onStepBackward?: () => void;
  /** Current playback speed. */
  speed: ReplaySpeed;
  /** Called when playback speed changes. */
  onSpeedChange: (speed: ReplaySpeed) => void;
  /** Called when replay mode is toggled on/off. */
  onActiveChange: (active: boolean) => void;
  /** Current seek position (0–1 normalized). */
  seekPosition?: number;
  /** Called when seek position changes. */
  onSeek?: (position: number) => void;
  /** Whether to show the seek slider. Default false. */
  showSeek?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-replay-controls-styles';

function ensureReplayControlsStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-replay-controls]:focus-within {
      box-shadow: 0 0 0 1px var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureReplayControlsStyles();
}

/* ----- Constants --------------------------------------------------------- */

const SPEED_OPTIONS = [
  { value: '0.5', label: '0.5x' },
  { value: '1', label: '1x' },
  { value: '2', label: '2x' },
  { value: '5', label: '5x' },
  { value: '10', label: '10x' },
];

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
};

const controlsRowStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  background: 'var(--ts-toolbar-bg)',
  border: '1px solid var(--ts-toolbar-border)',
  borderRadius: 'var(--ts-radius-md)',
  padding: 'var(--ts-space-1) var(--ts-space-2)',
  boxSizing: 'border-box',
};

const separatorStyle: CSSProperties = {
  width: 1,
  height: 20,
  background: 'var(--ts-toolbar-separator-color)',
  flexShrink: 0,
  margin: '0 var(--ts-space-1)',
};

const speedSelectStyle: CSSProperties = {
  minWidth: 70,
};

const seekContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  padding: '0 var(--ts-space-2)',
};

/* ----- Component --------------------------------------------------------- */

export function ReplayControls({
  active,
  playing,
  onPlayPause,
  onStepForward,
  onStepBackward,
  speed,
  onSpeedChange,
  onActiveChange,
  seekPosition,
  onSeek,
  showSeek = false,
}: ReplayControlsProps): React.JSX.Element {

  const handleSpeedChange = useCallback((value: string) => {
    onSpeedChange(parseFloat(value) as ReplaySpeed);
  }, [onSpeedChange]);

  const handleSeekChange = useCallback((values: number[]) => {
    if (values[0] !== undefined && onSeek) {
      onSeek(values[0] / 100);
    }
  }, [onSeek]);

  return (
    <div data-ts-replay-controls="" style={containerStyle}>
      <div style={controlsRowStyle} role="toolbar" aria-label="Replay controls" aria-orientation="horizontal">
        {/* Replay toggle */}
        <IconButton
          icon={<History size={16} />}
          label={active ? 'Exit replay mode' : 'Enter replay mode'}
          variant="ghost"
          size="sm"
          active={active}
          onClick={() => onActiveChange(!active)}
        />

        {active && (
          <>
            <div style={separatorStyle} role="separator" aria-orientation="vertical" />

            {/* Step backward */}
            {onStepBackward && (
              <IconButton
                icon={<SkipBack size={14} />}
                label="Step backward"
                variant="ghost"
                size="sm"
                onClick={onStepBackward}
              />
            )}

            {/* Play/Pause */}
            <IconButton
              icon={playing ? <Pause size={16} /> : <Play size={16} />}
              label={playing ? 'Pause replay' : 'Play replay'}
              variant="ghost"
              size="sm"
              onClick={onPlayPause}
            />

            {/* Step forward */}
            <IconButton
              icon={<SkipForward size={14} />}
              label="Step forward"
              variant="ghost"
              size="sm"
              onClick={onStepForward}
            />

            <div style={separatorStyle} role="separator" aria-orientation="vertical" />

            {/* Speed selector */}
            <div style={speedSelectStyle}>
              <Select
                options={SPEED_OPTIONS}
                value={String(speed)}
                onValueChange={handleSpeedChange}
                size="sm"
                label="Replay speed"
              />
            </div>
          </>
        )}
      </div>

      {/* Seek slider */}
      {active && showSeek && onSeek && (
        <div style={seekContainerStyle}>
          <Slider
            value={[Math.round((seekPosition ?? 0) * 100)]}
            onValueChange={handleSeekChange}
            min={0}
            max={100}
            step={1}
            label="Seek position"
          />
        </div>
      )}
    </div>
  );
}

ReplayControls.displayName = 'ReplayControls';
