/**
 * Shared market data hook — single source of truth for price ticks across all apps.
 *
 * Replaces per-app Zustand stores for price data. Every app (watchlist, chart,
 * screener, alerts, depth, feeds, analytics, editor) uses this one hook.
 *
 * Design:
 * - Tick storage in `useRef` (NOT React state) to avoid per-tick re-renders
 * - `requestAnimationFrame` coalescing caps renders at ~60fps regardless of tick rate
 * - `version` counter triggers selective re-render in consuming components
 * - `getQuote` / `getAllQuotes` are stable callbacks (reference-equal across renders)
 * - `initPriceBridge()` is idempotent — safe to call from multiple hook instances
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import { initPriceBridge, onPriceUpdate } from '../services/service-bridge';
import type { PriceTick } from '../services/price-store';

export interface MarketDataState {
  /** Get the latest quote for a specific symbol. */
  getQuote: (symbol: string) => PriceTick | null;
  /** Get all latest quotes. */
  getAllQuotes: () => ReadonlyMap<string, PriceTick>;
  /** Whether the price bridge has been initialized. */
  isConnected: boolean;
  /** Monotonically-increasing counter; changes trigger re-render via rAF coalescing. */
  version: number;
}

/**
 * Single source of truth hook for market data.
 *
 * Uses the shared price bridge (FDC3 `deskmodal.prices` channel) and stores
 * ticks in a `useRef` (not React state) to avoid per-tick re-renders.
 * Coalesces renders to `requestAnimationFrame` (max ~60fps).
 */
export function useMarketData(): MarketDataState {
  const ticksRef = useRef<Map<string, PriceTick>>(new Map());
  const dirtyRef = useRef(false);
  const rafRef = useRef<number | null>(null);
  const [version, setVersion] = useState(0);
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    initPriceBridge();
    setIsConnected(true);

    const unsub = onPriceUpdate((tick: PriceTick) => {
      ticksRef.current.set(tick.symbol, tick);

      if (!dirtyRef.current) {
        dirtyRef.current = true;
        rafRef.current = requestAnimationFrame(() => {
          dirtyRef.current = false;
          setVersion((v) => v + 1);
        });
      }
    });

    return () => {
      unsub();
      if (rafRef.current != null) {
        cancelAnimationFrame(rafRef.current);
      }
    };
  }, []);

  const getQuote = useCallback(
    (symbol: string): PriceTick | null => ticksRef.current.get(symbol) ?? null,
    [],
  );

  const getAllQuotes = useCallback(
    (): ReadonlyMap<string, PriceTick> => ticksRef.current,
    [],
  );

  return { getQuote, getAllQuotes, isConnected, version };
}
