/* -------------------------------------------------------------------------- */
/*  Number formatting utilities for financial components.                     */
/* -------------------------------------------------------------------------- */

const SUFFIXES: ReadonlyArray<{ threshold: number; suffix: string; divisor: number }> = [
  { threshold: 1_000_000_000_000, suffix: 'T', divisor: 1_000_000_000_000 },
  { threshold: 1_000_000_000, suffix: 'B', divisor: 1_000_000_000 },
  { threshold: 1_000_000, suffix: 'M', divisor: 1_000_000 },
  { threshold: 1_000, suffix: 'K', divisor: 1_000 },
];

/**
 * Formats a large number with an appropriate suffix.
 *
 * Examples:
 *   1_234_567   → "1.23M"
 *   42_500      → "42.50K"
 *   987         → "987.00"
 *   0.00345     → "0.00"
 */
export function formatCompactNumber(value: number, precision: number = 2): string {
  const abs = Math.abs(value);
  const sign = value < 0 ? '-' : '';

  for (const { threshold, suffix, divisor } of SUFFIXES) {
    if (abs >= threshold) {
      return `${sign}${(abs / divisor).toFixed(precision)}${suffix}`;
    }
  }

  return `${sign}${abs.toFixed(precision)}`;
}

/**
 * Formats a price value to a fixed number of decimal places.
 */
export function formatPrice(value: number, precision: number = 2): string {
  return value.toFixed(precision);
}
